INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('tecnologia', 'bachillerato', '{2}', 'La tecnología 5G y la nueva conectividad', 'La quinta generación de redes móviles, conocida como 5G, representa un salto cualitativo respecto a las generaciones anteriores al combinar velocidades de descarga muy superiores, latencias de apenas unos milisegundos y la capacidad de conectar simultáneamente cientos de miles de dispositivos por kilómetro cuadrado. Esta infraestructura se apoya en antenas de pequeñas celdas distribuidas, en técnicas de haz dirigido conocidas como beamforming y en el uso combinado de bandas bajas, medias y milimétricas. A diferencia del 4G, el 5G permite además el troceado de red, una técnica que divide la infraestructura en redes virtuales independientes optimizadas para distintos usos, como la industria 4.0, los vehículos conectados o la telemedicina. Las bajas latencias abren la puerta a aplicaciones hasta ahora inviables, como la cirugía remota asistida, la realidad aumentada colaborativa o la coordinación en tiempo real de robots en fábricas. Sin embargo, el despliegue plantea retos técnicos, económicos y regulatorios: la necesidad de multiplicar el número de estaciones base, el coste de las licencias del espectro, el consumo energético y la preocupación ciudadana por los posibles efectos sobre la salud, aunque los organismos internacionales competentes no han encontrado evidencias de riesgo en las emisiones actuales. A largo plazo, el 5G se concibe como la columna vertebral del internet de las cosas masivo y como un facilitador clave de la transformación digital en sectores estratégicos.',
'[{"pregunta":"¿Qué técnica divide la infraestructura 5G en redes virtuales independientes?","opciones":["Beamforming","Troceado de red","Multiplexación","Roaming"],"correcta":1},{"pregunta":"¿Qué aplicación aprovecha especialmente la baja latencia del 5G?","opciones":["Descarga de correos","Cirugía remota asistida","Navegación web básica","Radio digital"],"correcta":1},{"pregunta":"¿Qué permite la tecnología de beamforming?","opciones":["Emitir en todas las direcciones","Dirigir el haz hacia el dispositivo","Duplicar la batería","Reducir el coste del terminal"],"correcta":1},{"pregunta":"¿Qué reto económico del 5G menciona el texto?","opciones":["La gratuidad del espectro","El coste de las licencias y el despliegue","La abundancia de antenas","La falta de demanda"],"correcta":1}]'::jsonb),

('tecnologia', 'bachillerato', '{2}', 'Computación cuántica: principios y perspectivas', 'La computación cuántica aprovecha los fenómenos de la mecánica cuántica para procesar información de manera radicalmente distinta a la computación clásica. En lugar de bits que valen 0 o 1, utiliza cúbits, unidades capaces de existir en superposición de estados y de entrelazarse con otros cúbits, lo que permite representar y manipular enormes cantidades de información simultáneamente. Gracias a estos principios, algoritmos como el de Shor pueden factorizar números grandes en tiempo polinómico, amenazando los sistemas criptográficos actuales basados en claves públicas, y algoritmos como el de Grover pueden acelerar búsquedas en bases de datos no ordenadas. Sin embargo, construir un ordenador cuántico práctico es extraordinariamente complejo: los cúbits son muy sensibles al ruido, a la temperatura y a las vibraciones, lo que provoca errores que exigen sofisticadas técnicas de corrección. Las principales arquitecturas actuales utilizan cúbits superconductores enfriados casi al cero absoluto, trampas de iones, fotones o átomos neutros. Empresas tecnológicas y laboratorios públicos compiten por alcanzar la llamada ventaja cuántica sostenida, es decir, resolver problemas útiles de forma más eficiente que cualquier supercomputador clásico. Entre las aplicaciones más prometedoras figuran la simulación de moléculas para diseñar medicamentos, la optimización logística, la modelización de materiales y el aprendizaje automático cuántico. Frente a estas expectativas, los gobiernos impulsan planes estratégicos para formar talento, invertir en infraestructura y desarrollar criptografía resistente a la amenaza cuántica.',
'[{"pregunta":"¿Qué unidad sustituye al bit en la computación cuántica?","opciones":["El byte","El cúbit","El nibble","El token"],"correcta":1},{"pregunta":"¿Qué algoritmo cuántico amenaza a la criptografía actual?","opciones":["Grover","Shor","Euclides","Dijkstra"],"correcta":1},{"pregunta":"¿Por qué son difíciles de construir los ordenadores cuánticos?","opciones":["Porque necesitan mucho papel","Porque los cúbits son muy sensibles al ruido","Porque son lentos","Porque usan más tinta"],"correcta":1},{"pregunta":"¿Qué es la ventaja cuántica sostenida?","opciones":["Resolver problemas útiles mejor que un supercomputador clásico","Comprar más cúbits","Reducir el tamaño del chip","Eliminar los errores para siempre"],"correcta":0}]'::jsonb),

('tecnologia', 'bachillerato', '{2}', 'Big data y toma de decisiones basada en datos', 'El big data designa el conjunto de técnicas, infraestructuras y metodologías que permiten capturar, almacenar y analizar volúmenes masivos de datos procedentes de fuentes diversas, generados además a gran velocidad y con una enorme variedad de formatos. Estas tres características, conocidas clásicamente como las tres uves de volumen, velocidad y variedad, se han ampliado con otras como veracidad y valor, que ponen el acento en la calidad de los datos y en la capacidad de extraer conocimiento útil para la toma de decisiones. Las arquitecturas típicas combinan sistemas de almacenamiento distribuido, como los basados en Hadoop o en lagos de datos en la nube, con motores de procesamiento paralelo como Spark, capaces de analizar petabytes de información en plazos razonables. Sobre estas infraestructuras se aplican técnicas estadísticas, de minería de datos y de aprendizaje automático que permiten detectar patrones, segmentar clientes, anticipar averías, personalizar contenidos o mejorar la eficiencia energética. Los beneficios son innegables en campos como la sanidad, la logística, la banca, la administración pública o la investigación científica, pero también se plantean dilemas éticos y legales relacionados con la privacidad, el consentimiento informado, la discriminación algorítmica y la seguridad frente a ciberataques. Normativas como el Reglamento General de Protección de Datos europeo buscan equilibrar innovación y derechos fundamentales, exigiendo transparencia y responsabilidad en el tratamiento masivo de información personal.',
'[{"pregunta":"¿Cuáles son las tres uves clásicas del big data?","opciones":["Velocidad, volumen y variedad","Valor, vida y voluntad","Verdad, voz y visión","Vibración, volumen y voltaje"],"correcta":0},{"pregunta":"¿Qué motor de procesamiento paralelo se cita?","opciones":["Excel","Spark","Word","Access"],"correcta":1},{"pregunta":"¿Qué normativa europea regula el tratamiento de datos personales?","opciones":["LOMCE","RGPD","LOPJ","LOU"],"correcta":1},{"pregunta":"¿Qué dilema ético plantea el big data?","opciones":["La privacidad y la discriminación algorítmica","La falta de datos","El exceso de papel","El precio de los discos duros"],"correcta":0}]'::jsonb),

('tecnologia', 'bachillerato', '{2}', 'Blockchain: confianza distribuida', 'El blockchain, o cadena de bloques, es una tecnología de registro distribuido que permite almacenar información en una estructura de bloques enlazados criptográficamente y replicados en numerosos nodos de una red. Cada bloque contiene un conjunto de transacciones, una marca temporal y un resumen criptográfico del bloque anterior, de modo que cualquier modificación en un bloque antiguo obligaría a rehacer toda la cadena posterior, lo que resulta computacionalmente inviable en redes grandes. La confianza no depende de una autoridad central, sino de un mecanismo de consenso entre los participantes, como la prueba de trabajo o la prueba de participación, que garantiza que los nodos honestos terminan acordando una única versión válida del registro. Aunque popularmente se asocia con las criptomonedas, el blockchain encuentra aplicaciones más amplias en la trazabilidad de cadenas de suministro, la gestión de certificados académicos, el registro de derechos de autor, la tokenización de activos o los contratos inteligentes, programas que se ejecutan automáticamente al cumplirse ciertas condiciones. Entre sus limitaciones destacan el elevado consumo energético de algunos protocolos, los problemas de escalabilidad, la dificultad de corregir errores una vez registrados, la gobernanza compleja y la incertidumbre jurídica en muchos países. El desarrollo de redes más eficientes, la interoperabilidad entre cadenas y la regulación adecuada son factores clave para que esta tecnología se consolide como una infraestructura fiable y sostenible de confianza digital.',
'[{"pregunta":"¿Qué enlaza criptográficamente cada bloque con el anterior?","opciones":["Una firma manuscrita","Un resumen criptográfico (hash)","Una contraseña única","Un número de serie"],"correcta":1},{"pregunta":"¿De qué depende la confianza en el blockchain?","opciones":["De un banco central","Del consenso entre los nodos","Del Gobierno","De un notario tradicional"],"correcta":1},{"pregunta":"¿Qué son los contratos inteligentes?","opciones":["Programas que se ejecutan al cumplirse condiciones","Contratos firmados a mano","Acuerdos verbales","Documentos en papel"],"correcta":0},{"pregunta":"¿Qué limitación del blockchain destaca el texto?","opciones":["La ausencia de cifrado","El elevado consumo energético de algunos protocolos","Su gratuidad universal","La falta de aplicaciones"],"correcta":1}]'::jsonb),

('tecnologia', 'bachillerato', '{2}', 'Ciberseguridad en la era digital', 'La ciberseguridad agrupa las prácticas, herramientas y procesos destinados a proteger sistemas informáticos, redes, dispositivos y datos frente a accesos no autorizados, alteraciones o destrucción. En un contexto de creciente digitalización, las amenazas se han sofisticado hasta incluir ataques de ransomware que cifran información crítica a cambio de rescates, ataques de denegación de servicio que saturan infraestructuras, campañas de phishing que suplantan la identidad de organizaciones confiables o vulnerabilidades de día cero explotadas antes de que exista parche. La defensa se articula en varias capas: seguridad perimetral con cortafuegos y sistemas de detección de intrusos, seguridad del endpoint en los dispositivos finales, cifrado de datos en tránsito y en reposo, autenticación multifactor, copias de seguridad verificadas y segmentación de redes para contener incidentes. El factor humano sigue siendo el eslabón más débil, por lo que la formación y la sensibilización del personal son tan importantes como las herramientas técnicas. Las organizaciones adoptan marcos como ISO 27001 o las directrices del Centro Criptológico Nacional para gestionar riesgos de forma sistemática. A nivel europeo, directivas como NIS2 elevan las exigencias a operadores esenciales. La ciberseguridad se ha convertido, así, en una responsabilidad compartida entre empresas, administraciones y ciudadanía, indispensable para preservar la continuidad del negocio, la privacidad y la confianza en los servicios digitales.',
'[{"pregunta":"¿Qué hace un ataque de ransomware?","opciones":["Publica información","Cifra datos a cambio de rescate","Regala dispositivos","Mejora el rendimiento"],"correcta":1},{"pregunta":"¿Qué eslabón sigue siendo el más débil de la ciberseguridad?","opciones":["El software","El hardware","El factor humano","El cableado"],"correcta":2},{"pregunta":"¿Qué norma internacional se cita para gestionar la seguridad?","opciones":["ISO 9001","ISO 27001","ISO 14001","ISO 22000"],"correcta":1},{"pregunta":"¿Qué tipo de autenticación refuerza los accesos?","opciones":["Solo contraseña","Multifactor","Por voz del administrador","Ninguna"],"correcta":1}]'::jsonb),

('tecnologia', 'bachillerato', '{2}', 'Edge computing: procesamiento en el borde', 'El edge computing es un paradigma que desplaza parte del procesamiento y el almacenamiento desde la nube centralizada hacia el borde de la red, es decir, hacia los dispositivos o nodos cercanos al lugar donde se generan los datos. Esta aproximación surge como respuesta a las limitaciones de enviar toda la información a centros de datos remotos: latencias excesivas para aplicaciones críticas, consumo de ancho de banda, dependencia permanente de la conectividad y preocupaciones sobre privacidad. Al procesar los datos localmente, el edge permite tomar decisiones en tiempo real en escenarios como vehículos autónomos, fábricas inteligentes, sistemas de videovigilancia avanzada o dispositivos médicos. Complementa, más que sustituye, a la computación en la nube, que sigue siendo imprescindible para el almacenamiento masivo, el entrenamiento de modelos de inteligencia artificial y el análisis histórico a gran escala. Las arquitecturas modernas combinan ambos enfoques en un continuo que se denomina cloud-edge, distribuyendo las cargas según su criticidad y volumen. Tecnologías como los contenedores, la orquestación ligera y el 5G facilitan la adopción del edge al permitir desplegar servicios de forma flexible en una gran variedad de dispositivos heterogéneos. Entre los retos destacan la gestión unificada de miles de nodos, la ciberseguridad en entornos físicamente accesibles, la estandarización y el consumo energético. El edge computing se perfila como una pieza clave del internet de las cosas y de la digitalización industrial sostenible.',
'[{"pregunta":"¿Dónde procesa los datos el edge computing?","opciones":["En centros lejanos","Cerca del lugar donde se generan","En el móvil del usuario final únicamente","En un servidor central único"],"correcta":1},{"pregunta":"¿Qué problema ayuda a mitigar respecto a la nube centralizada?","opciones":["El exceso de pantallas","La latencia excesiva y el consumo de ancho de banda","La falta de electricidad","El coste del papel"],"correcta":1},{"pregunta":"¿Sustituye totalmente a la nube?","opciones":["Sí, siempre","No, la complementa","Solo en Europa","Solo de noche"],"correcta":1},{"pregunta":"¿Qué tecnología facilita el despliegue flexible en el borde?","opciones":["Los contenedores y la orquestación ligera","Los disquetes","Las redes analógicas","El télex"],"correcta":0}]'::jsonb),

('tecnologia', 'bachillerato', '{2}', 'Biotecnología industrial y bioeconomía', 'La biotecnología industrial, también llamada biotecnología blanca, aprovecha microorganismos, enzimas y células modificadas para producir de forma más eficiente y sostenible productos químicos, materiales, alimentos y energía. Frente a los procesos petroquímicos tradicionales, las rutas biotecnológicas permiten trabajar a temperaturas y presiones más bajas, reducir residuos tóxicos, utilizar materias primas renovables como residuos agrícolas o lignocelulósicos y obtener moléculas difíciles de sintetizar por métodos convencionales. La ingeniería genética, la biología sintética y la edición de genomas con herramientas como CRISPR han ampliado enormemente las posibilidades, permitiendo diseñar microorganismos a medida para producir biocombustibles, bioplásticos, fármacos, aromas, detergentes o aditivos alimentarios. Esta tecnología se integra en la llamada bioeconomía, un modelo que busca desacoplar el crecimiento económico del consumo de recursos fósiles, valorizando los biorresiduos y cerrando ciclos de materia. El papel de las biorrefinerías, capaces de transformar biomasa en múltiples productos de valor añadido, resulta análogo al de las refinerías petrolíferas, pero con un impacto ambiental sensiblemente menor si se gestionan adecuadamente. Los retos pasan por garantizar la disponibilidad sostenible de biomasa, controlar los posibles efectos ecológicos de organismos modificados, regular la bioseguridad y competir en costes con procesos ya consolidados. La biotecnología industrial se ha convertido en una herramienta estratégica para la transición ecológica y el desarrollo de una industria más limpia, circular y basada en el conocimiento.',
'[{"pregunta":"¿Cómo se llama también a la biotecnología industrial?","opciones":["Biotecnología roja","Biotecnología blanca","Biotecnología negra","Biotecnología azul"],"correcta":1},{"pregunta":"¿Qué herramienta reciente facilita editar genomas?","opciones":["MS-DOS","CRISPR","GPS","Excel"],"correcta":1},{"pregunta":"¿Qué son las biorrefinerías?","opciones":["Instalaciones que transforman biomasa en múltiples productos","Minas de carbón","Granjas de pollos","Plantas solares"],"correcta":0},{"pregunta":"¿Qué modelo económico impulsa la biotecnología industrial?","opciones":["La bioeconomía","La economía lineal","La economía del petróleo","La economía de trueque"],"correcta":0}]'::jsonb),

('tecnologia', 'bachillerato', '{2}', 'Energías renovables avanzadas', 'Las energías renovables avanzadas engloban tecnologías que van más allá de la eólica y la fotovoltaica convencionales para aprovechar recursos limpios de forma más eficiente, flexible y gestionable. Entre ellas figuran la eólica marina flotante, capaz de instalar aerogeneradores en aguas profundas donde el viento es más constante; la solar termoeléctrica con almacenamiento en sales fundidas, que permite producir electricidad varias horas después de la puesta de sol; el hidrógeno verde obtenido por electrólisis del agua con electricidad renovable, considerado clave para descarbonizar sectores como la industria pesada o el transporte de largo alcance; la geotermia profunda mejorada, la energía undimotriz y mareomotriz, y las bioenergías con captura de carbono. Estas tecnologías se integran en sistemas cada vez más digitalizados, donde redes eléctricas inteligentes, baterías de alta densidad y gestión avanzada de la demanda permiten equilibrar la variabilidad de las fuentes. La transición energética no solo implica producir más electricidad limpia, sino rediseñar el sistema completo: electrificar consumos, mejorar la eficiencia, reducir la dependencia exterior de combustibles fósiles y garantizar la seguridad del suministro. Los retos incluyen los altos costes iniciales, la obtención sostenible de minerales críticos, la planificación territorial respetuosa con la biodiversidad y la cohesión social frente a posibles impactos locales. Los planes europeos y nacionales fijan objetivos ambiciosos de neutralidad climática, en los que estas renovables avanzadas desempeñan un papel imprescindible.',
'[{"pregunta":"¿Qué permite la solar termoeléctrica con sales fundidas?","opciones":["Producir electricidad tras la puesta de sol","Evitar cualquier almacenamiento","Eliminar el mantenimiento","Generar solo de noche"],"correcta":0},{"pregunta":"¿Qué es el hidrógeno verde?","opciones":["Un gas natural","Hidrógeno obtenido por electrólisis con electricidad renovable","Un biocombustible fósil","Un tipo de gasolina"],"correcta":1},{"pregunta":"¿Qué aprovecha la eólica marina flotante?","opciones":["Vientos en aguas profundas","Corrientes fluviales","La energía nuclear","La radiación ultravioleta"],"correcta":0},{"pregunta":"¿Qué objetivo persigue la transición energética según el texto?","opciones":["Neutralidad climática y seguridad del suministro","Aumentar los combustibles fósiles","Reducir la electrificación","Eliminar las redes eléctricas"],"correcta":0}]'::jsonb),

('tecnologia', 'bachillerato', '{2}', 'Vehículos autónomos: tecnología y dilemas', 'Los vehículos autónomos integran sensores, algoritmos de inteligencia artificial y sistemas de control para circular con distintos grados de independencia respecto al conductor humano. La Sociedad de Ingenieros de Automoción define seis niveles de autonomía, del 0 al 5, que van desde la ausencia total de automatización hasta vehículos plenamente autónomos capaces de operar sin intervención humana en cualquier condición. Para percibir el entorno, estos vehículos combinan cámaras, radar, lidar, sensores ultrasónicos y receptores de posicionamiento por satélite, mientras que los algoritmos fusionan los datos, identifican objetos, predicen trayectorias y planifican maniobras. El aprendizaje profundo ha sido decisivo para mejorar el reconocimiento de peatones, señales y otros vehículos en entornos complejos. Los beneficios potenciales incluyen una reducción drástica de los accidentes causados por error humano, una mayor accesibilidad para personas con movilidad reducida, una optimización del tráfico y un menor consumo energético. Sin embargo, persisten numerosos retos: la fiabilidad en condiciones meteorológicas adversas, la ciberseguridad, la coexistencia con vehículos convencionales, la adaptación de infraestructuras y la enorme responsabilidad jurídica en caso de accidente. A ello se suman dilemas éticos, como las decisiones que debe tomar el sistema en situaciones inevitables, y los impactos laborales sobre profesionales del transporte. El despliegue real está siendo gradual, con pruebas en entornos controlados y servicios limitados, mientras reguladores y sociedad debaten el marco adecuado.',
'[{"pregunta":"¿Cuántos niveles de autonomía define la SAE?","opciones":["3","5","6","10"],"correcta":2},{"pregunta":"¿Qué sensor utiliza pulsos láser para mapear el entorno?","opciones":["Radar","Lidar","GPS","Micrófono"],"correcta":1},{"pregunta":"¿Qué técnica de IA mejora el reconocimiento de objetos?","opciones":["El aprendizaje profundo","El método Delphi","Las hojas de cálculo","La regla de tres"],"correcta":0},{"pregunta":"¿Qué dilema ético plantean los vehículos autónomos?","opciones":["La decisión en situaciones inevitables","La elección del color","El precio del combustible","El tipo de neumático"],"correcta":0}]'::jsonb),

('tecnologia', 'bachillerato', '{2}', 'Realidad virtual y realidad aumentada', 'La realidad virtual y la realidad aumentada son tecnologías de interfaz que transforman la relación entre las personas y la información digital. La realidad virtual sumerge al usuario en entornos tridimensionales completamente sintéticos mediante gafas o cascos que combinan pantallas, sensores de movimiento y audio envolvente, aislándolo del mundo físico y creando una fuerte sensación de presencia. La realidad aumentada, en cambio, superpone elementos digitales sobre el entorno real percibido a través de cámaras, gafas transparentes o proyecciones, enriqueciendo lo visible con información contextual sin sustituirlo. Entre ambas se sitúa la realidad mixta, que permite la interacción entre objetos físicos y virtuales. Las aplicaciones superan con creces el ámbito del entretenimiento: en medicina se usan para formar a cirujanos, planificar intervenciones o tratar fobias; en industria, para guiar montajes, realizar mantenimiento remoto con asistencia visual o diseñar productos en entornos colaborativos; en educación, para visitas virtuales a museos, laboratorios simulados o reconstrucciones históricas; en arquitectura, para presentar proyectos antes de construirlos. Los avances en pantallas de alta resolución, seguimiento ocular, captura de movimientos y gráficos en tiempo real han mejorado notablemente la experiencia, aunque todavía existen retos como el mareo, el peso de los dispositivos, el coste o la protección de datos biométricos. La interoperabilidad de contenidos y la definición del llamado metaverso abren un debate sobre el futuro de estas tecnologías, su impacto social y la necesidad de un diseño centrado en el bienestar.',
'[{"pregunta":"¿Qué ofrece la realidad virtual al usuario?","opciones":["Un entorno sintético inmersivo","Una película en 2D","Una llamada telefónica","Un correo electrónico"],"correcta":0},{"pregunta":"¿En qué se diferencia la realidad aumentada?","opciones":["Superpone elementos digitales sobre el entorno real","Aísla completamente del mundo físico","Solo funciona en televisores antiguos","No tiene aplicaciones médicas"],"correcta":0},{"pregunta":"¿Qué nombre recibe la combinación interactiva de físico y virtual?","opciones":["Realidad neutra","Realidad mixta","Realidad remota","Realidad sonora"],"correcta":1},{"pregunta":"¿Qué reto físico se menciona para los usuarios?","opciones":["El mareo y el peso de los dispositivos","La falta de contenidos","La ausencia de color","La lentitud del papel"],"correcta":0}]'::jsonb),

('tecnologia', 'bachillerato', '{2}', 'Smart grids: redes eléctricas inteligentes', 'Las smart grids o redes eléctricas inteligentes son infraestructuras que integran generación, transporte, distribución y consumo bajo sistemas digitales de medida, comunicación y control capaces de gestionar la electricidad de forma dinámica y bidireccional. A diferencia de la red tradicional, pensada para un flujo unidireccional desde grandes centrales hacia los consumidores, la red inteligente permite incorporar la generación distribuida procedente de paneles fotovoltaicos domésticos, pequeños aerogeneradores, baterías, vehículos eléctricos y sistemas de autoconsumo. Los contadores inteligentes ofrecen información en tiempo real sobre el consumo, lo que facilita tarifas dinámicas, programas de respuesta a la demanda y una mejor gestión de picos. Mediante sensores distribuidos, analítica avanzada y algoritmos predictivos, los operadores pueden anticipar incidencias, equilibrar oferta y demanda en pequeños intervalos, reducir pérdidas en la distribución y facilitar la integración masiva de renovables variables como la solar o la eólica. Las microrredes locales, capaces de funcionar incluso aisladas del sistema general, refuerzan la resiliencia frente a fallos o emergencias. Los retos son importantes: ciberseguridad de una infraestructura crítica interconectada, protección de datos personales de los consumidores, necesidad de grandes inversiones en automatización, formación técnica y armonización regulatoria. La transición hacia smart grids es considerada una condición indispensable para alcanzar una electrificación limpia, descarbonizar el transporte, la edificación y la industria, y hacer del consumidor un participante activo del sistema energético.',
'[{"pregunta":"¿Qué flujo permite la red inteligente?","opciones":["Bidireccional entre generación y consumo","Solo hacia el consumidor","Solo hacia la central","Ningún flujo"],"correcta":0},{"pregunta":"¿Qué ofrecen los contadores inteligentes?","opciones":["Información de consumo en tiempo real","Solo lecturas anuales","Gas natural","Calefacción gratuita"],"correcta":0},{"pregunta":"¿Qué son las microrredes?","opciones":["Sistemas locales capaces de funcionar aislados","Cables submarinos","Transformadores antiguos","Pilas domésticas"],"correcta":0},{"pregunta":"¿Qué riesgo destaca el texto en las smart grids?","opciones":["Ciberseguridad de infraestructura crítica","Exceso de viento","Falta de cables","Saturación del papel"],"correcta":0}]'::jsonb),

('tecnologia', 'bachillerato', '{2}', 'Nanotecnología: la ciencia de lo pequeño', 'La nanotecnología estudia, diseña y manipula la materia a escala nanométrica, entre uno y cien nanómetros, donde los materiales presentan propiedades físicas, químicas y biológicas distintas de las observadas en su forma macroscópica. A estas escalas, aspectos como la relación superficie-volumen, los efectos cuánticos y la reactividad química se vuelven determinantes, permitiendo diseñar nanomateriales con propiedades notables: nanotubos de carbono con gran resistencia mecánica y conductividad, nanopartículas metálicas con actividad catalítica o antimicrobiana, puntos cuánticos con emisión luminosa ajustable o grafeno con conductividad excepcional. Las aplicaciones atraviesan prácticamente todos los sectores. En medicina se desarrollan nanosistemas capaces de transportar fármacos hasta células concretas, reducir efectos secundarios y mejorar diagnósticos por imagen; en electrónica permiten miniaturizar componentes y explorar nuevas arquitecturas; en energía contribuyen a baterías más eficientes, células solares avanzadas y procesos de catálisis; en textiles, a tejidos con propiedades antibacterianas o autolimpiables; en tratamiento de aguas, a filtros y sensores de gran sensibilidad. Pese a este potencial, la nanotecnología plantea retos en cuanto a la evaluación de sus posibles efectos sobre la salud humana y el medio ambiente, ya que la escala a la que actúan los nanomateriales puede facilitar su paso a través de barreras biológicas. Por ello, la normativa exige evaluaciones de toxicidad, etiquetado adecuado y una investigación responsable que combine innovación con principios de precaución y transparencia.',
'[{"pregunta":"¿En qué rango de tamaños trabaja la nanotecnología?","opciones":["1 a 100 nanómetros","1 a 100 milímetros","1 a 100 metros","1 a 100 micrómetros"],"correcta":0},{"pregunta":"¿Qué propiedad tiene el grafeno?","opciones":["Conductividad excepcional","Fragilidad extrema","Radiactividad natural","Toxicidad elevada obligatoria"],"correcta":0},{"pregunta":"¿Para qué se usan los nanosistemas en medicina?","opciones":["Transportar fármacos a células concretas","Sustituir a los hospitales","Eliminar la consulta médica","Evitar las vacunas"],"correcta":0},{"pregunta":"¿Qué principio guía la investigación responsable en nanotecnología?","opciones":["Improvisación","Precaución y transparencia","Secreto absoluto","Ausencia de normas"],"correcta":1}]'::jsonb);

-- ============================================================================
-- PROGRAMACIÓN (2º Bachillerato) - 12 textos EBAU
-- ============================================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('programacion', 'bachillerato', '{2}', 'Arquitectura de microservicios', 'La arquitectura de microservicios propone descomponer una aplicación en un conjunto de servicios pequeños, autónomos y especializados, cada uno responsable de una capacidad de negocio concreta y capaz de desplegarse de forma independiente. Frente al modelo monolítico tradicional, donde todos los módulos se empaquetan y despliegan como una única pieza, los microservicios permiten que distintos equipos trabajen en paralelo, utilicen tecnologías adecuadas para cada problema y evolucionen sus componentes sin bloquear al resto. La comunicación entre servicios se realiza habitualmente mediante APIs ligeras sobre HTTP, colas de mensajería o eventos, favoreciendo el acoplamiento débil. Cada microservicio suele gestionar su propia base de datos, lo que garantiza su autonomía pero obliga a repensar la coherencia de los datos distribuidos. Entre las ventajas destacan la escalabilidad granular, la resiliencia frente a fallos aislados, la capacidad de actualización continua y la facilidad para incorporar nuevas tecnologías. Sin embargo, también introducen complejidad operacional: es necesario orquestar muchos componentes, monitorizarlos, garantizar la trazabilidad de las peticiones, gestionar la seguridad en cada frontera y afrontar retos como las transacciones distribuidas o las redes poco fiables. Adoptar microservicios sin la madurez adecuada en integración continua, automatización, observabilidad y cultura DevOps puede generar más problemas que beneficios. Por ello, se recomienda empezar por un monolito bien estructurado y extraer servicios solo cuando las necesidades del negocio y del sistema lo justifiquen.',
'[{"pregunta":"¿Qué caracteriza a los microservicios?","opciones":["Son pequeños, autónomos y desplegables por separado","Comparten una única base de datos grande","No se comunican entre sí","Son idénticos entre sí"],"correcta":0},{"pregunta":"¿Cómo suelen comunicarse entre ellos?","opciones":["Por APIs ligeras, mensajería o eventos","Por cable serie","Por disquete","Por correo postal"],"correcta":0},{"pregunta":"¿Qué desventaja se menciona?","opciones":["La complejidad operacional","La falta de flexibilidad","El monolitismo forzado","La ausencia de pruebas"],"correcta":0},{"pregunta":"¿Qué se recomienda antes de adoptar microservicios?","opciones":["Contar con madurez DevOps y observabilidad","Eliminar las pruebas","Usar solo un ordenador","Programar sin versionado"],"correcta":0}]'::jsonb),

('programacion', 'bachillerato', '{2}', 'Computación sin servidor (serverless)', 'La computación sin servidor, o serverless, es un modelo de ejecución en la nube en el que los desarrolladores despliegan fragmentos de código, habitualmente en forma de funciones, y el proveedor se encarga de aprovisionar, escalar y gestionar los recursos de infraestructura necesarios para ejecutarlas. Aunque el nombre puede inducir a error, los servidores siguen existiendo, pero resultan invisibles para quien programa: no es preciso mantener máquinas virtuales, sistemas operativos ni capacidades de escalado manual. El pago se realiza habitualmente por tiempo de ejecución y recursos consumidos, de modo que las funciones que no se invocan no generan coste. Este modelo se adapta bien a aplicaciones con cargas irregulares, tareas desencadenadas por eventos, procesamiento asíncrono, backends para móviles, APIs ligeras o automatizaciones internas. Entre sus ventajas figuran el ahorro en costes fijos, la rápida puesta en producción, el escalado automático prácticamente ilimitado y el enfoque de los equipos en la lógica de negocio. No obstante, también plantea retos específicos: tiempos de arranque en frío, límites en la duración y el tamaño de cada función, dependencia fuerte del proveedor, dificultad para reproducir entornos localmente y complejidad en la depuración distribuida. Arquitecturas modernas combinan funciones serverless con contenedores, bases de datos gestionadas y servicios de mensajería para construir sistemas desacoplados, flexibles y coste-eficientes, siempre evaluando cuándo esta aproximación resulta la más adecuada.',
'[{"pregunta":"¿Qué es serverless?","opciones":["Un modelo en el que el proveedor gestiona la infraestructura","Un programa sin código","Una red sin cables","Un sistema sin base de datos"],"correcta":0},{"pregunta":"¿Cómo se suele facturar?","opciones":["Por tiempo de ejecución y recursos consumidos","Por número de desarrolladores","Por líneas de código","Por peso del servidor"],"correcta":0},{"pregunta":"¿Qué problema es característico de serverless?","opciones":["El arranque en frío","La falta de electricidad","La imposibilidad de escalar","El exceso de hardware propio"],"correcta":0},{"pregunta":"¿Para qué casos se adapta bien?","opciones":["Cargas irregulares y tareas por eventos","Procesos de lotes gigantes siempre activos","Trabajos manuales en papel","Impresoras térmicas"],"correcta":0}]'::jsonb),

('programacion', 'bachillerato', '{2}', 'GraphQL: consulta flexible de APIs', 'GraphQL es un lenguaje de consulta y un entorno de ejecución para APIs desarrollado originalmente por una gran empresa de redes sociales y liberado como estándar abierto. Frente a las APIs REST tradicionales, donde cada endpoint devuelve una estructura predefinida, GraphQL permite al cliente describir con precisión los datos que necesita mediante una consulta explícita, recibiendo en una única respuesta exactamente los campos solicitados, ni más ni menos. Esto evita dos problemas habituales: el sobredimensionado, cuando el servidor envía más datos de los necesarios, y el subdimensionado, cuando es preciso realizar varias peticiones encadenadas para obtener toda la información. El servidor GraphQL expone un esquema fuertemente tipado que define los objetos, campos y relaciones disponibles, así como las operaciones de consulta, mutación y suscripción. Este esquema actúa como contrato estable entre cliente y servidor, facilita la documentación automática y permite a las herramientas de desarrollo validar consultas antes de ejecutarlas. Entre las ventajas destacan la flexibilidad para los clientes, la reducción del número de peticiones, la evolución gradual sin necesidad de versionar endpoints y una excelente experiencia para el desarrollador. También presenta retos, como la dificultad de cachear respuestas, la posibilidad de consultas maliciosamente complejas, la necesidad de proteger contra abusos y una curva de aprendizaje notable para los equipos acostumbrados a REST.',
'[{"pregunta":"¿Qué permite GraphQL al cliente?","opciones":["Describir los datos que necesita en la consulta","Recibir siempre todos los campos del modelo","Acceder a cualquier archivo del servidor","Ejecutar código del sistema operativo"],"correcta":0},{"pregunta":"¿Qué problemas evita respecto a REST?","opciones":["Sobredimensionado y subdimensionado","La compilación","La necesidad de HTTP","El uso de JSON"],"correcta":0},{"pregunta":"¿Qué define el esquema GraphQL?","opciones":["Los tipos, campos y operaciones disponibles","Los colores del interfaz","La marca del servidor","El sistema operativo cliente"],"correcta":0},{"pregunta":"¿Qué reto plantea GraphQL?","opciones":["La cacheabilidad y consultas costosas","La falta total de seguridad","El impedimento del HTTPS","La imposibilidad de validación"],"correcta":0}]'::jsonb),

('programacion', 'bachillerato', '{2}', 'WebSockets y comunicación en tiempo real', 'Los WebSockets son un protocolo de comunicación que establece una conexión persistente y bidireccional entre el cliente y el servidor a través de una misma conexión TCP, permitiendo intercambiar mensajes en ambos sentidos con muy baja latencia y sin la sobrecarga de abrir y cerrar múltiples peticiones HTTP. A diferencia del modelo tradicional de petición-respuesta, donde el cliente siempre inicia la comunicación, los WebSockets permiten que el servidor envíe datos al cliente en cualquier momento, habilitando casos de uso donde la actualización inmediata es fundamental. Esta tecnología es la base de muchas aplicaciones contemporáneas, como chats y mensajería, juegos multijugador en línea, cotizaciones financieras, seguimiento de vehículos, paneles de control de infraestructuras o colaboración en documentos compartidos. La conexión se inicia mediante una negociación HTTP estándar que luego se actualiza al protocolo WebSocket, aprovechando así la infraestructura existente y los mecanismos de seguridad como TLS. Entre las ventajas figuran el menor consumo de ancho de banda comparado con soluciones basadas en polling continuo, la latencia reducida y la capacidad de implementar flujos de datos complejos. Entre los retos se incluyen la necesidad de gestionar estado en el servidor, la escalabilidad horizontal, la coordinación entre instancias, la autenticación de conexiones persistentes y la recuperación frente a desconexiones. Complementados con bibliotecas de nivel superior y arquitecturas orientadas a eventos, los WebSockets se han convertido en un pilar de la web interactiva moderna.',
'[{"pregunta":"¿Qué tipo de conexión establecen los WebSockets?","opciones":["Persistente y bidireccional","De un solo envío","Unidireccional al servidor","Por correo electrónico"],"correcta":0},{"pregunta":"¿En qué aplicación son especialmente útiles?","opciones":["Chats y juegos multijugador en tiempo real","Lectores de libros físicos","Impresoras matriciales","Calculadoras de bolsillo"],"correcta":0},{"pregunta":"¿Cómo se inicia la conexión WebSocket?","opciones":["Mediante una negociación HTTP que luego se actualiza","Llamando por teléfono","Copiando un disquete","Enviando un fax"],"correcta":0},{"pregunta":"¿Qué reto se menciona para los WebSockets?","opciones":["La gestión del estado y la escalabilidad","La falta de navegadores compatibles","La imposibilidad de usar HTTPS","La ausencia de bibliotecas"],"correcta":0}]'::jsonb),

('programacion', 'bachillerato', '{2}', 'Progressive Web Apps', 'Las Progressive Web Apps, o PWA, son aplicaciones web que combinan las ventajas tradicionales del navegador con las capacidades típicas de las aplicaciones nativas, ofreciendo una experiencia cercana a la de las apps instaladas pero sin necesidad de pasar por tiendas oficiales. Una PWA es, en esencia, un sitio web que cumple una serie de requisitos: se sirve mediante HTTPS, es responsivo, funciona incluso cuando la conexión es intermitente o inexistente gracias a un service worker que gestiona la caché y las peticiones, puede instalarse en la pantalla de inicio del dispositivo y admite notificaciones push. El service worker actúa como un proxy programable entre la aplicación y la red, interceptando peticiones y permitiendo estrategias avanzadas de caché, precarga y sincronización en segundo plano. Las PWA se benefician de todas las ventajas de la web: enlaces compartibles, indexación por buscadores, despliegue inmediato sin aprobación de tiendas, coste reducido de mantenimiento al utilizar un único código base y actualizaciones transparentes para el usuario. Al mismo tiempo, limitan algunas desventajas históricas del web frente a las apps nativas al ofrecer rendimiento razonable, presencia en el dispositivo y acceso a ciertas APIs del sistema. No obstante, persisten algunas diferencias: el soporte de ciertas APIs varía según el sistema operativo y los navegadores, algunas funciones avanzadas siguen siendo exclusivas del mundo nativo y la integración con tiendas puede ser más limitada. Aun así, las PWA se han consolidado como una opción competitiva en multitud de casos.',
'[{"pregunta":"¿Qué componente permite a una PWA funcionar sin conexión?","opciones":["El service worker","El servidor SQL","El servidor de correo","El DNS"],"correcta":0},{"pregunta":"¿Por qué protocolo deben servirse las PWA?","opciones":["HTTP","HTTPS","FTP","SMTP"],"correcta":1},{"pregunta":"¿Qué característica comparte con las apps nativas?","opciones":["Se pueden instalar y enviar notificaciones push","Obligan a usar un lenguaje propietario","Se distribuyen solo en papel","Requieren hardware exclusivo"],"correcta":0},{"pregunta":"¿Qué ventaja sobre las tiendas de apps destaca?","opciones":["Despliegue inmediato sin aprobación","Mayor coste","Obligación de versionar","Acceso solo sin internet"],"correcta":0}]'::jsonb),

('programacion', 'bachillerato', '{2}', 'TypeScript: JavaScript con tipos', 'TypeScript es un lenguaje de programación que extiende JavaScript añadiendo un sistema de tipos estático opcional, interfaces, enumeraciones, genéricos y otras construcciones avanzadas que se comprueban en tiempo de compilación. Desarrollado y mantenido como proyecto abierto por una gran compañía tecnológica, compila a JavaScript estándar, lo que significa que el código TypeScript puede ejecutarse en cualquier entorno donde funcione JavaScript: navegadores, servidores con Node.js o entornos embebidos. El sistema de tipos de TypeScript detecta errores comunes antes de ejecutar el programa, como el acceso a propiedades inexistentes, la confusión entre cadenas y números o las llamadas a funciones con argumentos incompatibles. Además, facilita la navegación del código, el autocompletado, la refactorización segura y la documentación implícita gracias al análisis estático que realizan los editores modernos. TypeScript es gradual: permite introducir tipos poco a poco en una base de código JavaScript existente, combinando archivos tipados y no tipados. Su riqueza expresiva incluye tipos unión e intersección, tipos literales, inferencia, tipos condicionales y tipos mapeados, que habilitan patrones avanzados pero también pueden complicar la lectura para desarrolladores menos experimentados. En grandes proyectos con muchos colaboradores, el retorno de invertir en TypeScript suele ser claro: menos errores en producción, código más mantenible y una base común para la comunicación entre equipos. En proyectos pequeños o prototipos rápidos, en cambio, la sobrecarga puede no compensar siempre.',
'[{"pregunta":"¿Qué añade TypeScript a JavaScript?","opciones":["Un sistema de tipos estático","Un motor de bases de datos","Un servidor web","Un editor de imágenes"],"correcta":0},{"pregunta":"¿A qué compila TypeScript?","opciones":["A JavaScript estándar","A ensamblador","A Python","A SQL"],"correcta":0},{"pregunta":"¿Qué ventaja destaca el texto para grandes proyectos?","opciones":["Menos errores en producción y mantenibilidad","Ausencia de pruebas","Eliminación de equipos","Ninguna"],"correcta":0},{"pregunta":"¿Qué significa que TypeScript sea gradual?","opciones":["Se pueden combinar archivos tipados y no tipados","Solo acepta tipos complejos","Exige reescribirlo todo","Cambia de sintaxis cada mes"],"correcta":0}]'::jsonb),

('programacion', 'bachillerato', '{2}', 'Redux y la gestión del estado', 'Redux es una biblioteca de gestión de estado muy utilizada en aplicaciones de interfaz construidas con bibliotecas como React. Su propuesta central consiste en almacenar todo el estado de la aplicación en un único objeto inmutable, llamado store, y modificarlo exclusivamente a través de acciones, objetos que describen qué ha sucedido, y reductores, funciones puras que reciben el estado anterior y una acción y devuelven el nuevo estado. Estos tres principios, conocidos como única fuente de verdad, estado de solo lectura y cambios mediante funciones puras, facilitan razonar sobre el comportamiento del sistema, realizar depuración mediante viaje en el tiempo y escribir pruebas deterministas. Redux resulta especialmente útil en aplicaciones grandes donde múltiples componentes comparten estado, donde los flujos de datos son complejos o donde se necesita persistir, sincronizar o auditar los cambios. Sin embargo, su adopción también implica cierta verbosidad, una curva de aprendizaje y una sobrecarga que puede resultar innecesaria en aplicaciones sencillas. Para mitigarlo, el ecosistema ha desarrollado herramientas como Redux Toolkit, que reducen el boilerplate y aportan buenas prácticas por defecto, y middlewares para gestionar tareas asíncronas, efectos secundarios o llamadas a APIs. Alternativas como Zustand, MobX o la propia API de contexto ofrecen enfoques distintos, más ligeros o más basados en reactividad. La elección depende del tamaño del proyecto, la experiencia del equipo y la naturaleza del estado a gestionar.',
'[{"pregunta":"¿Dónde almacena Redux el estado?","opciones":["En un único store inmutable","En cada componente por separado","En cookies","En archivos XML"],"correcta":0},{"pregunta":"¿Cómo se modifica el estado?","opciones":["Mediante acciones y reductores","Editando el DOM directamente","Con sentencias SQL","Con ficheros de texto"],"correcta":0},{"pregunta":"¿Qué herramienta reduce el boilerplate de Redux?","opciones":["Redux Toolkit","Apache","Postgres","nginx"],"correcta":0},{"pregunta":"¿Cuándo es especialmente útil Redux?","opciones":["En aplicaciones grandes con estado compartido complejo","En ejercicios de una sola pantalla","En archivos estáticos","En presentaciones"],"correcta":0}]'::jsonb),

('programacion', 'bachillerato', '{2}', 'Desarrollo guiado por pruebas avanzado', 'El desarrollo guiado por pruebas, o TDD, es una práctica en la que el programador escribe primero una prueba automatizada que describe un comportamiento esperado, la ejecuta para confirmar que falla, implementa el mínimo código necesario para que pase y, finalmente, refactoriza el resultado manteniendo todas las pruebas verdes. Este ciclo de rojo-verde-refactor, aparentemente sencillo, tiene consecuencias profundas: obliga a diseñar desde la perspectiva del uso, fomenta funciones pequeñas y cohesivas, documenta el comportamiento del sistema mediante ejemplos ejecutables y reduce drásticamente el miedo a modificar el código. En su versión avanzada, el TDD se combina con otras técnicas como las dobles de pruebas para aislar dependencias, las pruebas de contrato entre servicios, las pruebas basadas en propiedades que generan entradas aleatorias para verificar invariantes, las pruebas de mutación para medir la calidad de la suite y las pruebas de rendimiento automatizadas. También se articula con el desarrollo guiado por comportamiento, que expresa los ejemplos en un lenguaje cercano al de negocio, y con el desarrollo orientado a aceptación, centrado en criterios verificables acordados con el cliente. Aplicar TDD a conciencia requiere disciplina, tiempo de aprendizaje y una infraestructura de integración continua que ejecute las pruebas con rapidez y fiabilidad. Los beneficios a medio plazo incluyen menos errores, una base de código más flexible, mejores diseños emergentes y equipos más confiados para evolucionar el software.',
'[{"pregunta":"¿Cuál es el ciclo característico del TDD?","opciones":["Rojo, verde, refactor","Compilar, correr, imprimir","Escribir, borrar, repetir","Planificar, reunir, documentar"],"correcta":0},{"pregunta":"¿Qué son las pruebas basadas en propiedades?","opciones":["Generan entradas aleatorias para verificar invariantes","Prueban solo valores nulos","Comprueban el color de la interfaz","Evalúan la velocidad de la red"],"correcta":0},{"pregunta":"¿Qué mide una prueba de mutación?","opciones":["La calidad de la suite de pruebas","La cantidad de variables","La velocidad del disco","El tiempo de compilación"],"correcta":0},{"pregunta":"¿Con qué enfoque se combina TDD para hablar el lenguaje del negocio?","opciones":["Desarrollo guiado por comportamiento","Programación lineal","Análisis numérico","Gestión contable"],"correcta":0}]'::jsonb),

('programacion', 'bachillerato', '{2}', 'Diseño guiado por el dominio', 'El diseño guiado por el dominio, o DDD, es una aproximación al desarrollo de software que pone el énfasis en comprender profundamente el ámbito del problema y en modelarlo con un lenguaje compartido entre desarrolladores y expertos del negocio. Esta aproximación reconoce que el mayor desafío de muchos proyectos no es técnico, sino conceptual: traducir reglas, procesos y decisiones del mundo real en código coherente y mantenible. Para ello, el DDD propone construir un modelo rico del dominio, expresado en un lenguaje ubicuo que todos los miembros del equipo utilizan consistentemente en conversaciones, documentación y código. El dominio se divide en contextos acotados, cada uno con su propio modelo y responsabilidad, evitando los modelos monolíticos que intentan abarcarlo todo y terminan siendo incoherentes. Dentro de cada contexto se identifican entidades con identidad estable, objetos de valor sin identidad, agregados que definen fronteras de consistencia, repositorios que gestionan la persistencia y servicios de dominio que encapsulan operaciones complejas. Los eventos de dominio representan hechos relevantes que pueden desencadenar reacciones en otras partes del sistema, favoreciendo arquitecturas orientadas a eventos. El DDD se apoya además en técnicas de descubrimiento colaborativo como el event storming, talleres visuales donde los equipos reconstruyen el flujo de eventos del negocio con ayuda de notas adhesivas. Aunque resulta especialmente útil en proyectos complejos y cambiantes, su aplicación requiere madurez, tiempo y colaboración estrecha con el negocio.',
'[{"pregunta":"¿Qué propone el DDD para comunicarse con el negocio?","opciones":["Un lenguaje ubicuo compartido","Diagramas exclusivamente técnicos","Correo electrónico formal","Consultas SQL"],"correcta":0},{"pregunta":"¿Qué son los contextos acotados?","opciones":["Subdivisiones con modelo y responsabilidad propia","Ventanas del sistema operativo","Categorías de usuarios","Tipos de pantalla"],"correcta":0},{"pregunta":"¿Qué técnica colaborativa menciona el texto?","opciones":["El event storming","La lluvia de ideas musical","El análisis DAFO","El diagrama de Gantt"],"correcta":0},{"pregunta":"¿Cuándo resulta especialmente útil el DDD?","opciones":["En proyectos complejos y cambiantes","En programas triviales","En ejercicios escolares","En cálculos aritméticos simples"],"correcta":0}]'::jsonb),

('programacion', 'bachillerato', '{2}', 'GraphQL frente a REST: comparativa', 'REST y GraphQL son dos enfoques para diseñar APIs con filosofías distintas que conviven en numerosos proyectos modernos. REST organiza la información en recursos identificados por URLs y utiliza los verbos del protocolo HTTP para describir las operaciones: GET para recuperar, POST para crear, PUT o PATCH para actualizar y DELETE para eliminar. Su simplicidad, su apoyo en mecanismos estándar de la web como la cacheabilidad por URL y su amplia adopción lo hacen una opción sólida para muchas APIs públicas y privadas. GraphQL, en cambio, expone un único endpoint al que se envían consultas estructuradas que detallan exactamente los datos requeridos. Esta flexibilidad resulta especialmente valiosa cuando distintos clientes, como una aplicación web y una móvil, necesitan información diferente a partir del mismo backend. GraphQL reduce el número de peticiones y evita tanto la descarga de datos innecesarios como los problemas de subdimensionado que obligaban a encadenar varias llamadas REST. Por el contrario, REST brilla por su simplicidad conceptual, su facilidad para cachear respuestas en proxies intermedios y su compatibilidad con herramientas existentes. GraphQL exige un esquema centralizado, una planificación cuidadosa de consultas costosas y mecanismos para limitar peticiones abusivas. Muchas organizaciones optan por soluciones híbridas: usan REST para operaciones sencillas o interoperabilidad con terceros y GraphQL para escenarios donde la flexibilidad del cliente aporta un valor claro, eligiendo herramientas según la naturaleza del producto y las necesidades de consumo de datos.',
'[{"pregunta":"¿Qué expone GraphQL frente a REST?","opciones":["Un único endpoint","Múltiples puertos TCP","Un servidor SMTP","Una tabla SQL"],"correcta":0},{"pregunta":"¿Qué ventaja tiene REST según el texto?","opciones":["La cacheabilidad por URL","La ausencia de verbos","La obligación de usar GraphQL","La imposibilidad de versionar"],"correcta":0},{"pregunta":"¿Cuándo aporta más valor GraphQL?","opciones":["Cuando distintos clientes necesitan datos diferentes","Cuando solo hay un cliente de texto","Cuando se usa papel","Cuando no hay red"],"correcta":0},{"pregunta":"¿Qué estrategia adoptan muchas organizaciones?","opciones":["Soluciones híbridas REST y GraphQL","Solo ensamblador","Solo telefonía","Solo correo postal"],"correcta":0}]'::jsonb),

('programacion', 'bachillerato', '{2}', 'Monitorización y observabilidad', 'La monitorización y la observabilidad son disciplinas imprescindibles para operar sistemas informáticos modernos, especialmente cuando están compuestos por múltiples servicios distribuidos, en entornos dinámicos y con alta disponibilidad. La monitorización tradicional se centra en vigilar un conjunto conocido de métricas e indicadores predefinidos, como el uso de CPU, la memoria, la latencia o el número de errores, y en disparar alertas cuando se superan determinados umbrales. La observabilidad, en cambio, persigue un objetivo más ambicioso: permitir formular preguntas nuevas sobre el estado interno del sistema a partir de los datos que este expone, sin necesidad de modificarlo ni de predecir de antemano todos los problemas posibles. Se apoya en tres pilares: las métricas, agregadas y eficientes para detectar tendencias y alertar; las trazas distribuidas, que siguen el recorrido de una petición a través de los servicios y revelan cuellos de botella; y los registros, secuencias de eventos textuales detallados que aportan contexto cuando las métricas y trazas no son suficientes. Herramientas abiertas como Prometheus, Grafana, Jaeger u OpenTelemetry han estandarizado buena parte de estas prácticas. La observabilidad exige instrumentar cuidadosamente el código, definir indicadores significativos de calidad de servicio, gestionar el coste de almacenamiento de los datos y proteger la información sensible. Equipos con buena observabilidad pueden diagnosticar incidentes más rápido, aprender del comportamiento real del sistema y tomar decisiones basadas en datos sobre capacidad, arquitectura y prioridades de mejora.',
'[{"pregunta":"¿Cuáles son los tres pilares de la observabilidad?","opciones":["Métricas, trazas y registros","Papel, bolígrafo y goma","CPU, GPU y RAM","HTML, CSS y JS"],"correcta":0},{"pregunta":"¿Para qué sirven las trazas distribuidas?","opciones":["Seguir peticiones entre servicios y detectar cuellos de botella","Cambiar el color del tema","Sumar columnas de Excel","Escribir poesía"],"correcta":0},{"pregunta":"¿Qué herramienta abierta se menciona para métricas?","opciones":["Prometheus","Photoshop","Excel","Blender"],"correcta":0},{"pregunta":"¿Qué diferencia observabilidad de monitorización?","opciones":["Permite formular preguntas nuevas sobre el estado interno","No usa datos","Solo mide CPU","Es más barata siempre"],"correcta":0}]'::jsonb),

('programacion', 'bachillerato', '{2}', 'Orquestación de contenedores con Kubernetes', 'La orquestación de contenedores resuelve el problema de desplegar, escalar y operar de forma automatizada numerosos contenedores distribuidos entre muchas máquinas físicas o virtuales. Kubernetes se ha consolidado como la herramienta de referencia en este ámbito, ofreciendo una plataforma abierta capaz de gestionar aplicaciones complejas en nubes públicas, privadas o híbridas. Su unidad básica de despliegue es el pod, que agrupa uno o varios contenedores estrechamente relacionados. Los despliegues describen el número deseado de réplicas y la estrategia de actualización, y los servicios exponen pods ante otros componentes o ante el exterior con un nombre estable, abstrayendo las direcciones cambiantes. El planificador decide en qué nodo ejecutar cada pod en función de los recursos disponibles y de las restricciones definidas, mientras que los controladores comparan de forma continua el estado real con el estado deseado y actúan para reconciliarlos. Kubernetes incorpora mecanismos de autoescalado horizontal, balanceo de carga, gestión de secretos y configuración, almacenamiento persistente y actualizaciones sin tiempo de inactividad. Alrededor del núcleo ha crecido un ecosistema muy amplio, con herramientas de empaquetado, despliegue continuo, mallas de servicios, monitorización y seguridad. A cambio de su potencia, Kubernetes presenta una complejidad considerable: curva de aprendizaje elevada, necesidades de infraestructura, dificultad operativa y riesgo de sobrediseño. Por eso conviene evaluar caso por caso si los beneficios justifican la inversión o si existen alternativas más ligeras.',
'[{"pregunta":"¿Cuál es la unidad básica de despliegue en Kubernetes?","opciones":["El pod","El contenedor aislado","El proceso","El núcleo del sistema"],"correcta":0},{"pregunta":"¿Qué hacen los servicios?","opciones":["Exponen pods con un nombre estable","Borran contenedores","Ejecutan bases de datos","Instalan el sistema operativo"],"correcta":0},{"pregunta":"¿Qué reconcilia el controlador?","opciones":["Estado real con estado deseado","Usuarios con contraseñas","Facturas con ingresos","Colores con sonidos"],"correcta":0},{"pregunta":"¿Qué riesgo destaca el texto sobre Kubernetes?","opciones":["Su complejidad y posible sobrediseño","La ausencia de herramientas","La falta de comunidad","La gratuidad excesiva"],"correcta":0}]'::jsonb);


