INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('valenciano', 'bachillerato', '{2}', 'La literatura valenciana de postguerra', 'La literatura valenciana va patir, com la resta de les lletres en llengua catalana, les conseqüències del règim franquista, que va imposar fortes limitacions a la publicació i a l''ensenyament en valencià. Després de la Guerra Civil, molts escriptors van haver d''optar entre el silenci, l''exili o una discreta resistència cultural. Les editorials, les revistes i les llibreries van desaparèixer o van reduir enormement la seua activitat, i els autors novells van trobar dificultats per a formar-se en la seua pròpia llengua. Tot i això, figures com Joan Fuster, Vicent Andrés Estellés o Enric Valor van aconseguir mantindre viva la literatura valenciana i, amb el temps, renovar-la. Fuster, amb els seus assaigs lúcids i combatius, va oferir una reflexió crítica sobre la identitat valenciana i la seua relació amb la cultura catalana. Estellés, des de la poesia, va donar veu al poble amb un llenguatge alhora senzill i poderós, marcat per la memòria, l''amor i el compromís. Enric Valor va dedicar-se a recuperar el valencià literari, amb novel·les i amb una obra lingüística que encara hui es consulta. La fi del franquisme va obrir una etapa de major llibertat creativa, acompanyada per noves editorials, premis literaris i una presència creixent en l''ensenyament. La literatura valenciana de postguerra és, per tant, una literatura d''obstinació i resistència que demostra com la creació artística pot sobreviure a les adversitats més dures.',
'[{"pregunta":"Quines dificultats va patir la literatura valenciana de postguerra?","opciones":["Limitacions de publicació i ensenyament","Un excés de subvencions","Massa lectors","Massa llibreries"],"correcta":0},{"pregunta":"Quin autor és conegut pels assaigs crítics?","opciones":["Joan Fuster","Pau Casals","Joan Miró","Raimon"],"correcta":0},{"pregunta":"Què va aportar Vicent Andrés Estellés?","opciones":["Una poesia senzilla i poderosa","Només novel·les històriques","Obres de teatre musicals","Tractats jurídics"],"correcta":0},{"pregunta":"Què va obrir la fi del franquisme?","opciones":["Una etapa de major llibertat creativa","El tancament d''editorials","L''abandonament de la llengua","La prohibició del valencià"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'La novel·la històrica en valencià', 'La novel·la històrica és un gènere amb una llarga tradició en les lletres en llengua catalana, i també en l''àmbit valencià ha produït obres destacades al llarg del darrer segle. Aquest tipus de narrativa combina la reconstrucció d''un passat concret amb una trama que barreja personatges històrics i ficticis, de manera que el lector pot aprofundir en una època mentre gaudeix d''una història. Per a l''escriptor, cal un treball de documentació meticulós, una sensibilitat pel llenguatge de cada moment i la capacitat de recrear escenaris creïbles sense caure en l''erudició excessiva. En el cas valencià, moltes novel·les històriques s''han ambientat en la Corona d''Aragó, en els segles de l''esplendor medieval, en les lluites entre moriscs i cristians, o en períodes com la Guerra de Successió i la pèrdua dels furs. Aquest gènere permet recuperar moments clau de la memòria col·lectiva i fer-los arribar a un públic ampli, sovint amb més força emotiva que els manuals d''història. També contribueix a reforçar el paper del valencià com a llengua literària capaç d''explorar temes universals, i a estimular l''interés dels lectors joves per l''estudi del passat. Algunes obres han estat adaptades al cinema, a la televisió o al teatre, ampliant la seua repercussió cultural. La novel·la històrica en valencià no es limita, així, a un exercici d''evocació nostàlgica, sinó que dialoga amb el present i convida a reflexionar sobre les identitats, els conflictes i les transformacions que configuren la societat actual.',
'[{"pregunta":"Què combina la novel·la històrica?","opciones":["Reconstrucció del passat i trama de ficció","Només estadístiques","Càlculs matemàtics","Receptes de cuina"],"correcta":0},{"pregunta":"En quins períodes s''han ambientat moltes obres valencianes?","opciones":["La Corona d''Aragó i la Guerra de Successió","L''època neolítica","L''imperi romà de Britànnia","L''Egipte faraònic"],"correcta":0},{"pregunta":"Què permet recuperar aquest gènere?","opciones":["Moments clau de la memòria col·lectiva","Preus de mercat","Models matemàtics","Receptes antigues"],"correcta":0},{"pregunta":"Què demostra la novel·la històrica respecte al valencià?","opciones":["Que és una llengua literària capaç de temes universals","Que no interessa ningú","Que només serveix per a gramàtiques","Que no té futur"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'Lingüística computacional i valencià', 'La lingüística computacional és la disciplina que aplica els mètodes de la informàtica a l''estudi i al processament del llenguatge natural. Els seus avanços han fet possible els traductors automàtics, els correctors gramaticals, els assistents de veu i moltes altres eines que hui utilitzem amb normalitat. Per a llengües com el valencià, el desenvolupament d''aquestes tecnologies és particularment important: si una llengua no disposa de recursos digitals prou robustos, corre el risc de quedar marginada en l''espai virtual i de perdre presència entre els usuaris més joves. Per això, universitats, centres d''investigació i institucions públiques han impulsat la creació de corpus lingüístics, diccionaris electrònics, analitzadors sintàctics i models d''intel·ligència artificial capaços de comprendre i generar textos en valencià. Els reptes són importants: cal disposar d''una gran quantitat de dades d''alta qualitat, treballar amb experts lingüistes i informàtics, i garantir que els resultats reflectisquen la diversitat dialectal i registre de la llengua. Els beneficis, però, són enormes: des d''una millor experiència dels parlants en els dispositius digitals fins al suport a la docència, la traducció professional o l''accessibilitat per a persones amb discapacitat. A mesura que els grans models de llengua s''estenen, és fonamental assegurar que el valencià hi tinga un lloc adequat, tant per raons culturals com per a garantir els drets lingüístics. La lingüística computacional és, així, una aliada estratègica per a la vitalitat del valencià en el segle XXI, tant en l''àmbit acadèmic com en la vida quotidiana.',
'[{"pregunta":"Què aplica la lingüística computacional?","opciones":["Mètodes informàtics a l''estudi del llenguatge","Només la gramàtica clàssica","Càlculs aritmètics bàsics","La música tradicional"],"correcta":0},{"pregunta":"Per què és rellevant per al valencià?","opciones":["Perquè permet mantindre la llengua en l''espai digital","Perquè limita els parlants","Perquè redueix el vocabulari","Perquè elimina les llengües"],"correcta":0},{"pregunta":"Quins recursos s''han creat?","opciones":["Corpus, diccionaris electrònics i analitzadors","Mapes antics","Pintures murals","Escultures"],"correcta":0},{"pregunta":"Què cal garantir en aquests models?","opciones":["Que reflectisquen la diversitat dialectal","Que prohibisquen els dialectes","Que ignoren la llengua","Que siguen secrets"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'La diglòssia actual al País Valencià', 'La diglòssia és una situació sociolingüística en què dues llengües conviuen en un mateix territori amb funcions desiguals: una és considerada de prestigi, adequada per als usos formals, mentre que l''altra queda restringida als àmbits informals, familiars o tradicionals. Al País Valencià, la relació entre el valencià i el castellà ha mostrat durant molt de temps trets clarament diglòssics, amb el castellà ocupant posicions centrals en l''administració, els mitjans de comunicació de masses i l''àmbit comercial, i amb el valencià limitat en molts contextos a les converses privades. Aquesta distribució no és natural ni inamovible: és el resultat d''unes polítiques i unes circumstàncies històriques concretes. Al llarg de les darreres dècades, la normalització lingüística ha intentat corregir aquesta situació, impulsant la presència del valencià en l''ensenyament, l''administració, la senyalització i els mitjans públics. Els resultats són mixtos: hi ha avanços significatius, com l''augment del coneixement escrit entre els joves o la publicació de més obres literàries i materials didàctics, però també retrocessos preocupants, amb una transmissió intergeneracional feble i una presència limitada en alguns sectors urbans. La diglòssia, doncs, continua sent una realitat en bona part del territori. Per a superar-la cal un treball continuat d''institucions, famílies i ciutadania que garantisca els drets lingüístics, valore la llengua com a patrimoni viu i ofrerisca als parlants oportunitats reals d''utilitzar-la en tots els àmbits de la vida social i professional.',
'[{"pregunta":"Què és la diglòssia?","opciones":["Una situació amb dues llengües de funcions desiguals","Una llengua única","Un dialecte perdut","Un accent regional"],"correcta":0},{"pregunta":"Quines posicions ha ocupat el castellà al País Valencià?","opciones":["Administració, mitjans i comerç","Només la cuina","Només la poesia","Només el teatre infantil"],"correcta":0},{"pregunta":"Què intenta corregir la normalització lingüística?","opciones":["La situació diglòssica","El clima","L''orografia","L''horari escolar"],"correcta":0},{"pregunta":"Quin retrocés es menciona?","opciones":["La transmissió intergeneracional feble","L''excés de llibres","Massa lectors","Massa escoles rurals"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'L''ecologia al País Valencià', 'El territori valencià presenta una gran diversitat d''ecosistemes, des de les muntanyes de l''interior fins a les zones humides del litoral, passant per boscos mediterranis, estepes i espais agrícoles tradicionals. Aquesta riquesa natural, però, està sotmesa a pressions importants. Les urbanitzacions a la costa, el turisme massiu en determinades zones, els incendis forestals, la contaminació dels aqüífers i les conseqüències del canvi climàtic amenacen espècies i hàbitats emblemàtics. L''Albufera de València, un dels aiguamolls més valuosos del Mediterrani, pateix des de fa dècades problemes de qualitat de l''aigua, de pèrdua de biodiversitat i de pressió agrícola. Altres espais protegits, com el Parc Natural del Montgó, la Marjal de Pego-Oliva o les Serres de Mariola i d''Espadà, afronten reptes similars. Davant aquesta situació, la societat valenciana ha desenvolupat una consciència ecològica creixent, reflectida en associacions, voluntariat ambiental, iniciatives ciutadanes i projectes educatius. Les institucions han ampliat les figures de protecció, promogut l''agricultura sostenible i impulsat programes de recuperació d''espècies. Tot i això, els recursos són sovint limitats i la coordinació entre administracions és complexa. L''ecologia valenciana no és només una qüestió tècnica: és una manera de repensar la relació amb el territori, la cultura, l''economia i les generacions futures. Protegir els paisatges i la biodiversitat exigeix un compromís col·lectiu que involucre tota la ciutadania, perquè el patrimoni natural és també un patrimoni cultural i una herència que determina en bona mesura la nostra qualitat de vida.',
'[{"pregunta":"Quin espai emblemàtic es menciona?","opciones":["L''Albufera de València","El Sàhara","La tundra","Els Alps"],"correcta":0},{"pregunta":"Quines pressions afecten el territori valencià?","opciones":["Urbanització, turisme massiu, incendis i contaminació","Només les nevades","Només les marees","Només els eclipsis"],"correcta":0},{"pregunta":"Què reflecteix la consciència ecològica creixent?","opciones":["Associacions i voluntariat ambiental","La desaparició d''ONG","L''abandonament del territori","El rebuig a la natura"],"correcta":0},{"pregunta":"Què exigeix protegir la biodiversitat?","opciones":["Un compromís col·lectiu","Un aïllament total","La desaparició dels ciutadans","L''oblit del territori"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'El periodisme valencià avui', 'El periodisme valencià viu un moment de transformacions profundes, marcat per la digitalització dels mitjans, els nous hàbits de consum informatiu i la necessitat de mantindre la presència de la llengua en l''espai comunicatiu. Els diaris tradicionals han vist reduir-se les seues tirades en paper, mentre que les edicions digitals, els podcasts, els canals de vídeo i les xarxes socials han guanyat protagonisme. Les redaccions són avui més petites i els professionals han d''assumir tasques múltiples: redactar, fotografiar, gravar vídeos i interactuar amb les audiències. Un dels reptes específics del periodisme valencià és garantir una oferta informativa plural i de qualitat en valencià, capaç de competir amb els grans mitjans en castellà i de respondre a les necessitats d''un públic divers. Mitjans públics com À Punt i projectes independents nascuts en les darreres dècades han contribuït a enriquir el panorama, però la sostenibilitat econòmica, la dependència de subvencions i la competència internacional són obstacles constants. Com en altres àmbits, el periodisme afronta la desinformació, les notícies falses i la polarització, fenòmens que exigeixen un treball rigorós de verificació i una educació mediàtica sòlida. Iniciatives de formació, premis professionals i col·laboracions amb universitats busquen reforçar la qualitat. Al cap i a la fi, un periodisme valencià actiu i lliure és una peça clau per a la salut democràtica, la visibilitat de la cultura pròpia i la capacitat de la ciutadania per a comprendre i transformar la realitat que l''envolta cada dia.',
'[{"pregunta":"Què marca les transformacions del periodisme valencià?","opciones":["La digitalització i els nous hàbits informatius","El retorn al telègraf","La desaparició del paper abans de 1900","El rebuig a la tecnologia"],"correcta":0},{"pregunta":"Què ha de fer un periodista avui?","opciones":["Assumir tasques múltiples","Només redactar a mà","Només gravar cintes de casset","Cap mena de tasca"],"correcta":0},{"pregunta":"Quin mitjà públic es menciona?","opciones":["À Punt","BBC","CNN","Al Jazeera"],"correcta":0},{"pregunta":"Quin fenomen afronta el periodisme actual?","opciones":["La desinformació i les notícies falses","L''excés de rigor absolut","La gratuïtat universal","L''abundància d''errors de càlcul"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'Cinema valencià: històries pròpies', 'El cinema valencià és una realitat cultural que, malgrat les dificultats econòmiques i la competència dels grans estudis internacionals, ha aconseguit aportar mirades pròpies al panorama audiovisual. Les pel·lícules en valencià, curtmetratges, documentals i produccions col·laboratives han abordat temes propis del territori, des d''històries familiars i socials fins a memòries col·lectives, tradicions, conflictes lingüístics o paisatges emblemàtics. Directors com Berlanga, tot i que treballava majoritàriament en castellà, són figures referencials per a la cultura valenciana i han inspirat generacions posteriors. Més recentment, noves veus han trobat en els festivals de cinema una plataforma per a donar a conéixer la seua obra. Les ajudes públiques, les col·laboracions amb la televisió pública i l''ús d''escoles de cinema locals són pilars fonamentals per al sector. No obstant això, els reptes continuen sent grans: pressupostos limitats, dificultats de distribució, sales que tanquen i la competència dels serveis d''streaming, que dicten nous ritmes i formats. La digitalització, paradoxalment, també obri oportunitats per a estrenar pel·lícules en línia, arribar a audiències internacionals i dialogar amb comunitats de la diàspora. Fer cinema en valencià suposa un acte de compromís amb la llengua i amb la memòria, i contribueix a un imaginari audiovisual més plural i divers. El públic valencià, al seu torn, té un paper fonamental: assistir a les sales, recomanar aquestes obres i reclamar una programació rica en valencià és una manera de sostindre un cinema que narra allò que ens és proper i alhora obri la porta al món.',
'[{"pregunta":"Quins temes tracta sovint el cinema valencià?","opciones":["Històries socials, memòries i paisatges propis","Només guerres galàctiques","Només ciència-ficció pura","Només animació japonesa"],"correcta":0},{"pregunta":"Quins pilars sostenen el sector?","opciones":["Ajudes públiques i televisió pública","Exclusivament Hollywood","Només empreses multinacionals","Només mecenes privats del segle XIX"],"correcta":0},{"pregunta":"Quin repte afronta avui el cinema valencià?","opciones":["Pressupostos limitats i distribució difícil","Excés de sales buides a tot arreu","Manca total de tècnics","Prohibició del format vídeo"],"correcta":0},{"pregunta":"Com pot contribuir el públic?","opciones":["Assistint a les sales i reclamant programació","Ignorant les estrenes","Evitant anar al cinema","Prohibint les pel·lícules"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'La gastronomia valenciana: patrimoni i identitat', 'La gastronomia valenciana és molt més que una suma de receptes: és una expressió rica de la història, del territori i de la forma de viure d''un poble. La paella, símbol reconegut internacionalment, és només un dels plats que formen part d''una tradició culinària diversa que inclou arrossos de moltes varietats, verdures de l''horta, peixos del Mediterrani, carns de l''interior i fruites de secà i de regadiu. Els mercats, les festes populars i les celebracions familiars han transmés durant generacions els gustos, els procediments i el vocabulari propi de cada comarca. En els darrers anys, la gastronomia ha viscut un doble fenomen. Per una banda, s''ha professionalitzat gràcies a cuiners que, amb una formació sòlida i una creativitat notable, han portat plats tradicionals a l''alta cuina, guanyant premis internacionals i situant el País Valencià en els mapes gastronòmics del món. Per una altra, ha crescut la consciència sobre la necessitat de protegir els productes locals, les varietats autòctones i les tècniques artesanals davant la pressió de la industrialització i de l''homogeneïtzació global. Denominacions d''origen, segells de qualitat i fires agroalimentàries contribueixen a aquesta tasca. La gastronomia també té una dimensió educativa important: transmet valors com la temporalitat, l''aprofitament dels aliments, la sostenibilitat i el respecte pel treball pagès i pesquer. Menjar en valencià, en definitiva, és un acte cultural que enllaça passat, present i futur, i que reforça el sentit de comunitat, el vincle amb la terra i l''orgull d''un patrimoni compartit per a totes les generacions.',
'[{"pregunta":"Quin plat és símbol internacional de la cuina valenciana?","opciones":["La paella","El sushi","El cuscús","La pizza"],"correcta":0},{"pregunta":"Què s''ha professionalitzat en els darrers anys?","opciones":["La gastronomia, amb cuiners premiats","El transport de mercaderies","El comerç d''armes","La banca privada"],"correcta":0},{"pregunta":"Què ajuda a protegir els productes locals?","opciones":["Denominacions d''origen i segells de qualitat","La desaparició dels mercats","La prohibició de les fires","L''oblit total de les receptes"],"correcta":0},{"pregunta":"Quins valors transmet la gastronomia?","opciones":["Temporalitat, sostenibilitat i respecte pel treball","Menyspreu pel producte","Indiferència ambiental","Excessiu individualisme"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'Música contemporània valenciana', 'L''escena musical valenciana contemporània és especialment viva, amb grups i artistes que conjuguen la llengua pròpia amb influències globals com el rock, el pop, el hip-hop, l''electrònica o les músiques del món. Formacions com Obrint Pas, Zoo, La Fúmiga, Aspencat o Smoking Souls han aconseguit portar el valencià als grans festivals, a les ràdios i a un públic jove que troba en aquestes cançons un espai d''identificació. Cantar en valencià, en un moment de desigual presència de la llengua en els mitjans de masses, és una acció cultural i política al mateix temps, que visibilitza la vitalitat d''una llengua capaç d''expressar des de l''amor i la festa fins a la crítica social. La música tradicional també continua viva gràcies a colles, escoles i festivals que recuperen instruments com la dolçaina i el tabal, o danses i cants d''arrel antiga. Els intercanvis entre artistes de tot l''àmbit lingüístic, del Principat a les Illes, fan possible un ecosistema cultural més ampli i enriquidor. El sector afronta, com en altres llocs, els reptes de la digitalització, la precarietat dels artistes emergents i la competència d''un mercat saturat de continguts. Plataformes locals, premis, festes majors i festivals són plataformes essencials per a fer-se visibles. Per al públic, descobrir, assistir als concerts i compartir aquestes cançons és una manera concreta de sostindre un panorama musical en valencià que enforteix la llengua i estimula la creativitat d''una nova generació plena de talent i d''idees.',
'[{"pregunta":"Amb quins gèneres es combina la música valenciana contemporània?","opciones":["Rock, pop, hip-hop i electrònica","Només música clàssica","Només òpera italiana","Només música barroca"],"correcta":0},{"pregunta":"Quins instruments tradicionals es recuperen?","opciones":["Dolçaina i tabal","Baix elèctric exclusivament","Sintetitzadors analògics","Mòbils només"],"correcta":0},{"pregunta":"Què simbolitza cantar en valencià?","opciones":["Una acció cultural i política alhora","Un simple passatemps","Una moda passatgera","Un joc infantil"],"correcta":0},{"pregunta":"Com pot ajudar el públic?","opciones":["Descobrint, assistint i compartint les cançons","Oblidant les bandes locals","Ignorant els festivals","Menyspreant la llengua"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'Fent Memòria: la recuperació del passat', 'Fer memòria, en el sentit més ampli, és recordar i comprendre allò que ha passat per aprendre''n i construir un futur més just. Al País Valencià, la recuperació de la memòria històrica ha estat especialment important en relació amb la Guerra Civil, la postguerra i el franquisme. Durant dècades, moltes famílies van viure marcades pel silenci sobre les víctimes, els exilis, les represàlies i les represaliats, un silenci que dificultava el duel i l''elaboració col·lectiva. Amb la transició i, sobretot, amb els moviments ciutadans dels darrers anys, aquesta situació ha començat a canviar. Associacions de familiars, historiadors, arxivers i institucions han impulsat exhumacions de fosses comunes, estudis acadèmics, publicacions, exposicions i homenatges públics. L''objectiu no és buscar revenja, sinó restituir la dignitat de les víctimes, reconéixer els drets humans vulnerats i facilitar la reconciliació des de la veritat. Un altre vessant essencial és l''educació: introduir aquests temes en les aules, amb materials rigorosos i propostes pedagògiques adaptades, permet a les generacions joves comprendre que la democràcia i les llibertats no són regals gratuïts, sinó conquestes col·lectives que cal protegir. La memòria també inclou les lluites culturals, socials i lingüístiques del passat, que ajuden a entendre les arrels del present. Fer memòria no significa viure mirant enrere, sinó reconéixer els fils que connecten les experiències dels avantpassats amb les decisions actuals i aprendre a valorar els drets, les institucions i la convivència plural que avui podem gaudir.',
'[{"pregunta":"Per què és important fer memòria?","opciones":["Per aprendre del passat i construir un futur més just","Per a oblidar-ho tot","Per a castigar els altres","Per a ignorar les víctimes"],"correcta":0},{"pregunta":"Què han impulsat les associacions i institucions?","opciones":["Exhumacions, estudis i homenatges","Destrucció d''arxius","Silenci forçós","Prohibició de parlar"],"correcta":0},{"pregunta":"Quin paper té l''educació?","opciones":["Transmetre que la democràcia és una conquesta col·lectiva","Ignorar totalment la història","Substituir la història per ficció","Suprimir els arxius"],"correcta":0},{"pregunta":"Què no significa fer memòria?","opciones":["Viure mirant enrere","Reconéixer els drets","Comprendre el present","Valorar la convivència"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'Intel·ligència artificial i llengua', 'La intel·ligència artificial, especialment els grans models de llengua, ha obert un nou escenari per a l''aprenentatge, la comunicació i el treball intel·lectual. Aquestes eines són capaces de redactar textos, respondre preguntes, traduir entre idiomes i ajudar a corregir errors, cosa que les converteix en aliades potencials per a estudiants, docents i professionals. Per a llengües com el valencià, la presència en aquests sistemes és essencial: si els grans models no entenen ni generen la llengua amb qualitat, els parlants poden acabar utilitzant més una altra llengua, fins i tot en contextos privats o informals. Per això, investigadors, empreses i institucions impulsen la creació de dades específiques, models adaptats i avaluacions per a comprovar que la qualitat de la resposta en valencià és satisfactòria. L''ús responsable d''aquestes tecnologies també suposa reflexionar sobre els seus riscos: la possible reproducció de prejudicis, la creació de continguts enganyosos, la dependència excessiva o la pèrdua de competències si es delega a la màquina el que hauríem de fer nosaltres. En l''àmbit educatiu, docents i alumnes han de trobar un equilibri que aprofite les oportunitats sense renunciar a l''esforç personal i al pensament crític. En l''àmbit cultural, aquestes eines poden facilitar la recuperació de textos antics, la traducció d''obres i l''accés a la informació en valencià. La combinació d''una comunitat parlant activa, una investigació científica robusta i polítiques lingüístiques adequades resultarà clau per a garantir el futur digital del valencià.',
'[{"pregunta":"Què són els grans models de llengua?","opciones":["Sistemes d''IA capaços de redactar i traduir textos","Videojocs exclusivament","Programes d''edició d''imatges","Sistemes de navegació per satèl·lit"],"correcta":0},{"pregunta":"Per què és important la presència del valencià?","opciones":["Perquè els parlants no abandonen la llengua en contextos digitals","Perquè els models són opcionals","Perquè la llengua no importa","Perquè el valencià no té futur"],"correcta":0},{"pregunta":"Quins riscos menciona el text?","opciones":["Prejudicis, continguts enganyosos i dependència","Absència total d''errors","Massa diccionaris","Massa acadèmics"],"correcta":0},{"pregunta":"Què resulta clau per al futur digital del valencià?","opciones":["Comunitat parlant, investigació i polítiques","Només la indiferència","Només la prohibició","Només el silenci"],"correcta":0}]'::jsonb),

('valenciano', 'bachillerato', '{2}', 'El patrimoni oral valencià', 'El patrimoni oral del País Valencià comprén un conjunt d''expressions culturals transmeses de pares a fills al llarg dels segles: cançons tradicionals, rondalles, llegendes, refranys, dites, jocs infantils, cants de treball i romanços. Aquesta herència, més fràgil que la pedra o el paper, depén exclusivament de la veu i la memòria dels qui la custodien, i per això ha corregut el risc de desaparéixer en les societats modernes, dominades per mitjans audiovisuals i ritmes accelerats. Afortunadament, durant les darreres dècades s''ha desenvolupat una tasca important de recopilació i estudi acadèmic. Folkloristes, etnògrafs i grups universitaris han enregistrat testimonis d''avis i àvies, transcrit textos, analitzat variants comarcals i publicat obres que fan accessible aquest tresor a un públic més ampli. Les escoles també han incorporat rondalles i cançons al seu currículum, mentre que col·les, festivals i trobades locals els mantenen vius en l''espai públic. El patrimoni oral no es limita a un valor nostàlgic: és una font insubstituïble d''informació sobre la llengua, les creences, els oficis, els menjars, el paisatge i la mentalitat d''altres èpoques. Ens ajuda a comprendre d''on venim i a entendre les transformacions que ha experimentat la societat. També ens ofereix recursos creatius: molts escriptors, músics i artistes contemporanis s''inspiren en aquestes fonts per a les seues obres. Preservar el patrimoni oral és, per tant, una responsabilitat compartida entre famílies, institucions i creadors, i una via fonamental per a mantindre la riquesa cultural valenciana plenament viva.',
'[{"pregunta":"Què inclou el patrimoni oral?","opciones":["Cançons, rondalles, llegendes, refranys i jocs","Només diccionaris","Només còdexs medievals","Només llistes de lleis"],"correcta":0},{"pregunta":"De qui depén aquesta herència?","opciones":["De la veu i la memòria dels qui la custodien","D''una base de dades única","D''un sol llibre","Dels gens biològics"],"correcta":0},{"pregunta":"Qui ha fet tasca de recopilació?","opciones":["Folkloristes, etnògrafs i grups universitaris","Només empreses privades","Només turistes estrangers","Només ambaixadors"],"correcta":0},{"pregunta":"Quina informació aporta?","opciones":["Sobre llengua, creences, oficis i paisatge","Només sobre economia digital","Només sobre ciència aeroespacial","Només sobre informàtica"],"correcta":0}]'::jsonb);


