INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('geografia', 'bachillerato', '{2}', 'La agricultura ecológica en España', 'La agricultura ecológica se ha consolidado en España como una alternativa al modelo productivista convencional que durante décadas priorizó los rendimientos a corto plazo sobre la salud de los suelos, la biodiversidad y la calidad de los alimentos. Basada en el uso de técnicas que prescinden de pesticidas de síntesis y de fertilizantes químicos, la agricultura ecológica recurre a rotaciones de cultivos, abonos orgánicos, control biológico de plagas y variedades adaptadas al medio. España figura hoy entre los países europeos con mayor superficie dedicada a este modelo, con un protagonismo destacado de comunidades como Andalucía, Castilla-La Mancha, Extremadura o Cataluña. Los productos ecológicos certificados cuentan con garantías oficiales y encuentran mercado tanto en la exportación como en el consumo interno, impulsado por una creciente sensibilidad hacia la alimentación saludable. Sus beneficios ambientales son notables: mejor retención de agua en el suelo, mayor biodiversidad de insectos y aves, reducción de la contaminación de los acuíferos y menor huella de carbono en muchos casos. También ofrece oportunidades para revitalizar zonas rurales y fijar población, al tratarse de un modelo que suele generar más empleo por hectárea que el intensivo. Entre los retos destacan la estructura minifundista, la necesidad de formación técnica, la dependencia de subvenciones en algunas fases, los problemas de distribución eficiente y la competencia con productos convencionales de menor precio. Para crecer de manera sostenida, la agricultura ecológica española necesita políticas coherentes, apoyo logístico y consumidores informados capaces de valorar la calidad más allá del precio.',
'[{"pregunta":"¿Qué técnicas utiliza la agricultura ecológica?","opciones":["Rotaciones, abonos orgánicos y control biológico","Pesticidas químicos masivos","Monocultivo sin rotación","Herbicidas sintéticos exclusivamente"],"correcta":0},{"pregunta":"¿Qué comunidades destacan en este modelo?","opciones":["Andalucía, Castilla-La Mancha, Extremadura","Galicia exclusivamente","País Vasco exclusivamente","Asturias solo"],"correcta":0},{"pregunta":"¿Qué beneficio ambiental se menciona?","opciones":["Menor contaminación de acuíferos","Mayor erosión","Aumento de residuos plásticos","Mayor deforestación"],"correcta":0},{"pregunta":"¿Qué oportunidad rural ofrece?","opciones":["Revitalizar zonas rurales y fijar población","Despoblar los campos","Cerrar caminos","Eliminar la ganadería"],"correcta":0}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'Despoblación rural: la España vaciada', 'La despoblación de amplias zonas del interior peninsular, conocida como la España vaciada, constituye uno de los grandes retos territoriales del siglo XXI. Provincias como Soria, Teruel, Cuenca, Zamora o Guadalajara presentan densidades de población comparables a las de las regiones menos pobladas de Europa, con municipios que han perdido la mitad o más de sus habitantes en las últimas décadas. La combinación de bajísima natalidad, envejecimiento extremo, escaso relevo generacional y limitados servicios públicos ha llevado a la desaparición progresiva de escuelas, consultorios médicos, comercios y oficinas bancarias en numerosos pueblos. Las causas de la despoblación son históricas: el éxodo rural masivo durante el desarrollismo de los años sesenta, la mecanización agrícola, la falta de oportunidades laborales diversificadas y la fuerte atracción de las áreas metropolitanas marcaron un proceso que se ha mantenido en el tiempo. Sin embargo, en los últimos años ha surgido una mayor conciencia social y política sobre el fenómeno. Movimientos ciudadanos, plataformas territoriales y partidos provinciales han logrado situar la España vaciada en la agenda nacional. La Estrategia frente al Reto Demográfico, los fondos europeos de recuperación y los planes de inversión en infraestructuras digitales y transporte buscan ofrecer respuestas. Algunas experiencias positivas, como la llegada de neorrurales, el turismo sostenible, la producción agroalimentaria de calidad o los proyectos de energía renovable, muestran que existen caminos posibles, aunque modestos, para revertir parcialmente el declive. El futuro dependerá de una visión integral que combine servicios, empleo, conectividad y reconocimiento cultural.',
'[{"pregunta":"¿Qué provincias sufren especialmente despoblación?","opciones":["Soria, Teruel, Cuenca, Zamora","Madrid y Barcelona","Sevilla y Valencia","Málaga y Alicante"],"correcta":0},{"pregunta":"¿Qué proceso histórico marcó la despoblación?","opciones":["El éxodo rural del desarrollismo","La industrialización del siglo XVII","La colonización romana","La Reconquista"],"correcta":0},{"pregunta":"¿Qué planes buscan dar respuesta?","opciones":["Estrategia frente al Reto Demográfico y fondos europeos","Planes de abandono total","Programas de expulsión","Políticas de cierre"],"correcta":0},{"pregunta":"¿Qué experiencia positiva se menciona?","opciones":["Neorrurales, turismo sostenible y renovables","Despoblación acelerada","Desmantelamiento de servicios","Abandono escolar masivo"],"correcta":0}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'Turismo sostenible en España', 'España es una de las principales potencias turísticas mundiales, con un sector que representa una parte significativa del PIB y genera millones de empleos directos e indirectos. No obstante, el modelo basado en el turismo masivo de sol y playa ha mostrado sus limitaciones: saturación de ciertos destinos, presión sobre recursos hídricos y energéticos, degradación de ecosistemas costeros, inflación inmobiliaria, estacionalidad extrema y conflictos sociales con la población local. En este contexto, el turismo sostenible se presenta como una alternativa imprescindible para conciliar desarrollo económico, protección ambiental y bienestar social. Esta modalidad promueve destinos menos saturados, estancias más largas, experiencias vinculadas al patrimonio natural y cultural, y un consumo responsable. Se apoya en criterios como la eficiencia energética de los alojamientos, la gestión del agua, el fomento del transporte público, la valorización de la gastronomía y artesanía locales, y la participación efectiva de la comunidad en las decisiones. Rutas de senderismo, turismo rural, ecoturismo en espacios protegidos, enoturismo y turismo cultural son algunos de los segmentos en crecimiento. Políticas públicas y certificaciones ayudan a orientar el sector. El reto consiste en garantizar que el turismo sostenible no sea solo una etiqueta de marketing, sino un cambio estructural que reduzca realmente la huella ambiental y mejore las condiciones laborales. El papel del turista, al elegir destinos, transportes y hábitos, resulta tan decisivo como el de los operadores y las administraciones para construir un modelo turístico capaz de durar en el tiempo sin comprometer el territorio ni el bienestar de sus habitantes.',
'[{"pregunta":"¿Qué modelo turístico muestra limitaciones?","opciones":["El turismo masivo de sol y playa","El ecoturismo","El turismo rural","El senderismo"],"correcta":0},{"pregunta":"¿Qué promueve el turismo sostenible?","opciones":["Estancias más largas y consumo responsable","Saturación extrema","Rápidos paseos en coche","Cruceros masivos exclusivamente"],"correcta":0},{"pregunta":"¿Qué segmentos están en crecimiento?","opciones":["Ecoturismo, enoturismo y turismo cultural","Turismo de consumismo","Ninguno","Solo cruceros"],"correcta":0},{"pregunta":"¿Qué papel tiene el turista?","opciones":["Decisivo al elegir destinos y hábitos","Irrelevante","Nulo","Pasivo absolutamente"],"correcta":0}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'Energías renovables en España', 'España cuenta con un enorme potencial para las energías renovables gracias a su elevada insolación, a una geografía favorable para el viento y a una tradición temprana en la instalación de parques eólicos y solares. El mix energético del país ha experimentado un cambio acelerado en los últimos años: la participación del carbón ha caído drásticamente, mientras que la eólica, la fotovoltaica y la hidráulica representan una parte creciente de la generación eléctrica. Las centrales nucleares siguen aportando una fracción estable, aunque su papel a medio plazo es objeto de debate. Comunidades como Castilla y León, Aragón, Extremadura, Andalucía y Castilla-La Mancha concentran buena parte de las instalaciones renovables del país, aprovechando sus amplias superficies rurales y sus recursos naturales. El Plan Nacional Integrado de Energía y Clima fija objetivos ambiciosos de reducción de emisiones, de aumento de renovables en el consumo final y de mejora de la eficiencia energética, en línea con las metas europeas de neutralidad climática para mediados de siglo. Entre los retos destacan la adaptación de la red eléctrica para integrar generación distribuida, el almacenamiento mediante baterías o hidrógeno, la cohesión social en zonas que acogen grandes parques, la protección de la biodiversidad en las zonas afectadas y la planificación territorial cuidadosa. España también se posiciona como exportador potencial de hidrógeno verde y de tecnología renovable hacia otros países europeos, con un sector industrial cada vez más consolidado que genera empleo cualificado y oportunidades de desarrollo rural.',
'[{"pregunta":"¿Qué ventajas naturales tiene España para las renovables?","opciones":["Elevada insolación y buena geografía eólica","Clima polar","Escasa insolación","Vientos inexistentes"],"correcta":0},{"pregunta":"¿Qué plan nacional fija los objetivos energéticos?","opciones":["El Plan Nacional Integrado de Energía y Clima","El Plan Marshall","El Plan Hidráulico","El Plan Minero"],"correcta":0},{"pregunta":"¿Qué comunidades concentran muchas instalaciones?","opciones":["Castilla y León, Aragón, Extremadura","País Vasco exclusivamente","Baleares exclusivamente","Ceuta y Melilla"],"correcta":0},{"pregunta":"¿Qué reto se menciona?","opciones":["Adaptación de la red y almacenamiento","Falta total de viento","Inexistencia de sol","Cierre de todas las renovables"],"correcta":0}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'El transporte de alta velocidad en España', 'La red ferroviaria de alta velocidad española, iniciada en 1992 con la línea Madrid-Sevilla, se ha convertido en una de las más extensas del mundo. Nuevas líneas han conectado sucesivamente Madrid con Barcelona, Valencia, Málaga, Valladolid, Galicia o el País Vasco, transformando la movilidad interurbana y reduciendo drásticamente los tiempos de viaje. El impacto de la alta velocidad ha sido significativo: las ciudades conectadas han visto mejorar su accesibilidad, su atractivo turístico y su integración en el sistema productivo nacional. En algunos trayectos, el tren ha llegado a competir eficazmente con el avión, con ventajas ambientales evidentes dada la menor huella de carbono del ferrocarril. También ha contribuido a cohesionar el territorio, acercando provincias tradicionalmente periféricas al centro y facilitando desplazamientos cotidianos para estudiantes, profesionales y familias. No obstante, el modelo ha recibido críticas. Se ha señalado el elevado coste de las infraestructuras, la limitada rentabilidad económica de algunas líneas, la concentración radial en torno a Madrid frente a ejes transversales menos desarrollados, o el efecto sobre la competitividad de las ciudades intermedias. La liberalización del mercado ferroviario, la llegada de operadores privados y las tarifas más variadas han reabierto el debate sobre cómo garantizar un servicio público de calidad sin comprometer la competencia. Mirando al futuro, la alta velocidad debe integrarse en un sistema multimodal que combine trenes convencionales, cercanías, autobuses y movilidad urbana sostenible para responder a los retos climáticos y territoriales.',
'[{"pregunta":"¿Cuándo se inauguró la primera línea de alta velocidad española?","opciones":["1985","1992","2000","2012"],"correcta":1},{"pregunta":"¿Qué impacto tuvo en la movilidad?","opciones":["Redujo drásticamente los tiempos de viaje","Los aumentó","No cambió nada","Aumentó las emisiones"],"correcta":0},{"pregunta":"¿Qué crítica se menciona?","opciones":["La concentración radial en torno a Madrid","La falta absoluta de estaciones","El exceso de líneas secundarias","La ausencia de trenes"],"correcta":0},{"pregunta":"¿En qué debe integrarse la alta velocidad en el futuro?","opciones":["En un sistema multimodal","En un monopolio privado","En autopistas de peaje","En líneas de barco"],"correcta":0}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'Los parques nacionales españoles', 'España cuenta con una red de parques nacionales que protege algunos de los paisajes más singulares y valiosos del país, desde las cumbres pirenaicas de Ordesa y Monte Perdido hasta las lagunas salobres de las Tablas de Daimiel, pasando por los volcanes canarios del Teide, los hayedos de Aigüestortes, las islas del Archipiélago de Cabrera o las dehesas de Monfragüe. La figura del parque nacional, la más alta de las categorías españolas de protección, reconoce espacios de excepcional valor ecológico, geológico, paisajístico o cultural. Su gestión corresponde a las comunidades autónomas, en coordinación con el organismo estatal competente. Estos espacios desempeñan funciones múltiples: conservar ecosistemas representativos, preservar especies amenazadas, ofrecer oportunidades educativas y recreativas, apoyar la investigación científica y promover un turismo respetuoso. Los visitantes, cuando los recorren con sensibilidad y respeto a las normas, se convierten en aliados de su protección. Sin embargo, los parques nacionales afrontan retos importantes. El cambio climático altera regímenes hídricos, produce episodios de sequía o de inundación, favorece incendios más virulentos y desplaza especies. La presión turística en algunos lugares genera saturación, erosión de senderos y conflictos de uso. La conciliación con las actividades tradicionales, como la ganadería extensiva o el aprovechamiento forestal sostenible, es clave para el apoyo de las comunidades locales. Además, la financiación estable y la coordinación entre administraciones son condiciones imprescindibles. Los parques nacionales constituyen, en definitiva, una herencia que debe ser protegida y transmitida a las generaciones futuras como un tesoro natural compartido y común.',
'[{"pregunta":"¿Qué ejemplo de parque nacional se cita en los Pirineos?","opciones":["Ordesa y Monte Perdido","Teide","Daimiel","Monfragüe"],"correcta":0},{"pregunta":"¿A quién corresponde la gestión principal?","opciones":["Las comunidades autónomas","Una empresa privada","Un organismo europeo","Un único ayuntamiento"],"correcta":0},{"pregunta":"¿Qué reto afrontan los parques?","opciones":["El cambio climático y la presión turística","La abundancia de fondos","El exceso de lluvia permanente","La falta total de visitantes"],"correcta":0},{"pregunta":"¿Con qué actividades hay que conciliar?","opciones":["Ganadería extensiva y aprovechamiento sostenible","Minería a cielo abierto","Fábricas químicas","Autopistas privadas"],"correcta":0}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'Urbanización de la costa española', 'La costa mediterránea española ha experimentado durante las últimas décadas una intensa urbanización vinculada al desarrollo del turismo y al crecimiento residencial. Provincias como Alicante, Málaga, Almería o Girona muestran extensos tramos litorales transformados en conjuntos residenciales, complejos hoteleros, puertos deportivos, campos de golf y autopistas. Este proceso, acelerado desde los años sesenta y reactivado en varios ciclos inmobiliarios posteriores, ha generado importantes beneficios económicos: empleo, atracción de inversión, inserción en los circuitos turísticos internacionales y modernización de infraestructuras. No obstante, también ha provocado efectos ambientales y sociales preocupantes. La destrucción de dunas, marismas y bosques costeros ha reducido hábitats valiosos y disminuido la biodiversidad. El consumo de suelo ha sido elevado, con urbanizaciones que a menudo permanecen semivacías buena parte del año, y la presión sobre los recursos hídricos tensiona a los acuíferos, sobre todo en zonas áridas. Los problemas de erosión litoral se agravan por la urbanización de la primera línea, y el cambio climático, con su previsible subida del nivel del mar, amplifica los riesgos. Desde el punto de vista social, el encarecimiento del suelo y de la vivienda dificulta el acceso de la población residente y alimenta procesos de gentrificación. Las políticas de ordenación del territorio, la Ley de Costas y los planes de regeneración litoral tratan de poner límites, proteger tramos vírgenes y restaurar zonas degradadas. La experiencia acumulada muestra la necesidad de un desarrollo más equilibrado, que concilie actividad económica, protección ambiental y derechos de los habitantes permanentes.',
'[{"pregunta":"¿Qué provincias muestran intensa urbanización costera?","opciones":["Alicante, Málaga, Almería, Girona","Soria, Teruel, Cuenca","Burgos, Palencia, León","Álava, Guipúzcoa, Vizcaya"],"correcta":0},{"pregunta":"¿Qué efecto ambiental se destaca?","opciones":["Destrucción de dunas y bosques costeros","Aumento de zonas vírgenes","Restauración natural automática","Desaparición de la erosión"],"correcta":0},{"pregunta":"¿Qué amplifica los riesgos litorales?","opciones":["La subida del nivel del mar","La disminución del turismo","La falta de infraestructuras","El frío extremo"],"correcta":0},{"pregunta":"¿Qué norma intenta proteger la costa?","opciones":["La Ley de Costas","La Ley General Tributaria","La Ley de Patentes","La Ley del Deporte"],"correcta":0}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'El reto demográfico: envejecimiento y familias', 'El reto demográfico combina varios procesos simultáneos que transforman la estructura de la población española. El envejecimiento es uno de los más visibles: la esperanza de vida supera los 83 años y el porcentaje de mayores de 65 años crece sin pausa, mientras que el número de nacimientos se mantiene en cifras históricamente bajas. La tasa de fecundidad se sitúa en torno a 1,2 hijos por mujer, muy por debajo del nivel de reemplazo generacional. A ello se suma el aumento en la edad del primer hijo, la diversificación de los modelos familiares, la importancia creciente de los hogares unipersonales y los flujos migratorios, que aportan una componente joven y diversa a la pirámide. Las implicaciones son muy amplias. El sistema de pensiones afronta un desafío estructural al cambiar la relación entre activos y pasivos. La sanidad y la atención a la dependencia deben reforzarse, con necesidades crecientes de profesionales cualificados y recursos tecnológicos. El mercado laboral cambia, con nuevas demandas de formación y aprendizaje a lo largo de la vida. Las ciudades deben adaptarse con viviendas accesibles, transportes amigables y espacios públicos para todas las edades. Las políticas públicas tratan de combinar medidas de conciliación laboral y familiar, fomento de la natalidad, integración de las personas migrantes y cuidado de los mayores. Más allá de los números, el reto demográfico obliga a repensar la solidaridad intergeneracional, el contrato social y la manera de valorar el tiempo, el trabajo y los cuidados en una sociedad longeva y plural que sigue transformándose con rapidez.',
'[{"pregunta":"¿Qué tasa de fecundidad tiene España aproximadamente?","opciones":["1,2 hijos por mujer","2,5 hijos por mujer","3,0 hijos por mujer","0,5 hijos por mujer"],"correcta":0},{"pregunta":"¿Qué sistema se ve particularmente desafiado?","opciones":["El sistema de pensiones","El sistema de transporte aéreo","El sistema postal","El sistema bancario exclusivamente"],"correcta":0},{"pregunta":"¿Qué aportan los flujos migratorios?","opciones":["Una componente joven y diversa","Solo mayores","Ningún cambio","Aumento del envejecimiento"],"correcta":0},{"pregunta":"¿Qué replanteamiento obliga a hacer el reto demográfico?","opciones":["La solidaridad intergeneracional y el contrato social","La abolición de la sanidad","El cierre de las escuelas","La desaparición del empleo"],"correcta":0}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'Cambio climático en España', 'El cambio climático es una realidad que afecta ya de manera palpable al territorio español. Los datos muestran un aumento sostenido de las temperaturas medias, olas de calor más frecuentes e intensas, sequías recurrentes, episodios de lluvias torrenciales, incendios forestales de gran magnitud y alteraciones en los ecosistemas. España, por su posición mediterránea, figura entre las regiones europeas más vulnerables a estos fenómenos. Las consecuencias se dejan notar en sectores clave como la agricultura, donde cambian los calendarios de los cultivos y se acentúan las pérdidas por estrés hídrico; en el turismo, con temporadas cada vez más irregulares; en los recursos hídricos, con embalses que descienden peligrosamente en ciertos años; en la salud, con más días de calor extremo; en la biodiversidad, con especies desplazadas o amenazadas; y en la costa, con una creciente vulnerabilidad al aumento del nivel del mar. Las ciudades españolas adaptan su planificación con zonas verdes, refugios climáticos, cubiertas reflectantes y mejoras en la gestión del agua. El Plan Nacional de Adaptación al Cambio Climático y las estrategias autonómicas y locales buscan anticipar impactos y reducir vulnerabilidades. A la vez, España se compromete a reducir sus emisiones mediante la descarbonización energética, la promoción del transporte sostenible, la eficiencia y la fiscalidad ambiental. Todo ello en el marco de los objetivos europeos e internacionales. El éxito dependerá de la coherencia entre políticas, del papel activo del sector privado y de la implicación ciudadana, porque el cambio climático exige respuestas colectivas a gran escala.',
'[{"pregunta":"¿Por qué España es especialmente vulnerable?","opciones":["Por su posición mediterránea","Por su latitud polar","Por sus montañas bajas","Por su clima oceánico único"],"correcta":0},{"pregunta":"¿Qué sector agrícola se ve afectado?","opciones":["Cambian calendarios y hay estrés hídrico","Aumentan los rendimientos","No se ve afectado","Se moderniza sin problemas"],"correcta":0},{"pregunta":"¿Qué estrategia nacional se cita?","opciones":["El Plan Nacional de Adaptación al Cambio Climático","El Plan Hidrológico de 1932","El Plan General Contable","El Plan Marshall"],"correcta":0},{"pregunta":"¿De qué depende el éxito?","opciones":["Coherencia política, sector privado y ciudadanía","De una sola persona","Del azar","De una sola ley"],"correcta":0}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'Gestión del agua y sequías', 'El agua es un recurso estratégico en España, donde coexisten regiones con precipitaciones abundantes y otras marcadas por la escasez estructural. La gestión del agua se ha organizado tradicionalmente mediante grandes embalses, canales y trasvases, que han permitido garantizar el suministro a ciudades, regadíos y actividades industriales. En las últimas décadas, el enfoque ha evolucionado hacia una gestión integrada por cuencas, impulsada por la Directiva Marco del Agua europea, que exige alcanzar un buen estado ecológico de las masas de agua. Las sequías, cada vez más frecuentes e intensas en un contexto de cambio climático, ponen a prueba todo el sistema. Los episodios severos afectan a embalses, acuíferos, cultivos, ecosistemas y abastecimientos urbanos. Las cuencas mediterráneas son particularmente vulnerables, con una demanda elevada y una oferta irregular. Las respuestas combinan varias herramientas: mejoras en el ahorro y la eficiencia, modernización de regadíos, reutilización de aguas depuradas, desalación en zonas costeras, sensibilización ciudadana, planes especiales de sequía y tarifas que incentiven el uso responsable. La agricultura, principal consumidor de agua, se enfrenta a decisiones complejas sobre qué cultivos son adecuados, qué técnicas de riego resultan más eficientes y cómo proteger los rendimientos sin sobreexplotar acuíferos. Los conflictos entre usos agrícolas, urbanos y ambientales son habituales y requieren diálogo y planificación transparente. El futuro de la gestión del agua en España pasa por la adaptación al cambio climático, la innovación tecnológica, la participación social y la consideración del agua no solo como un recurso económico sino también como un bien ambiental imprescindible.',
'[{"pregunta":"¿Qué directiva europea impulsa la gestión integrada por cuencas?","opciones":["La Directiva Marco del Agua","La Directiva de Ruido","La Directiva de Residuos","La Directiva de Aves"],"correcta":0},{"pregunta":"¿Qué zonas son particularmente vulnerables?","opciones":["Las cuencas mediterráneas","La cuenca del Miño","Las zonas cantábricas","Las islas Azores"],"correcta":0},{"pregunta":"¿Qué herramienta tecnológica se cita en zonas costeras?","opciones":["La desalación","La nucleosíntesis","La telemetría solar","La pirólisis"],"correcta":0},{"pregunta":"¿Quién es el principal consumidor de agua?","opciones":["La agricultura","El turismo de cruceros","La iluminación pública","Los bomberos"],"correcta":0}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'Pesca sostenible y mar español', 'La pesca es una actividad tradicional en las costas españolas que ha dado lugar a un sector con gran peso económico, cultural y social. La flota pesquera española figura entre las más importantes de la Unión Europea y faena tanto en caladeros nacionales como en aguas internacionales. A lo largo de los años, sin embargo, la sobreexplotación de determinadas especies, la pérdida de hábitats marinos, la contaminación y el cambio climático han puesto en cuestión la sostenibilidad del modelo. Las capturas de algunas especies emblemáticas han disminuido y las tallas mínimas, los períodos de veda y las cuotas europeas tratan de regular el esfuerzo pesquero. La pesca sostenible busca compaginar la actividad económica con la conservación de los recursos. Se apoya en criterios científicos aportados por institutos de investigación, en una gestión adaptativa que ajusta las cuotas a la evolución de las poblaciones, en la lucha contra la pesca ilegal y en la trazabilidad de los productos. También implica renovar la flota con barcos más eficientes y seguros, mejorar las condiciones laborales de los trabajadores del mar y proteger zonas especialmente sensibles mediante reservas marinas. La acuicultura responsable puede complementar la pesca extractiva, aunque debe gestionarse con rigor para evitar impactos ambientales. El consumidor juega un papel importante al preferir productos con etiquetas de sostenibilidad y al diversificar las especies que elige. La pesca sostenible es, por tanto, una tarea colectiva que involucra pescadores, científicos, administraciones, mercados y ciudadanía, esencial para garantizar la continuidad de un recurso valioso y de todo un modo de vida.',
'[{"pregunta":"¿Qué problema afecta al modelo pesquero?","opciones":["La sobreexplotación de especies","La falta de agua salada","La escasez de barcos antiguos","La ausencia total de peces"],"correcta":0},{"pregunta":"¿Qué herramientas regulan el esfuerzo?","opciones":["Cuotas, vedas y tallas mínimas","Aranceles universales","Permisos de esquí","Licencias de caza mayor"],"correcta":0},{"pregunta":"¿Qué rol tiene la acuicultura responsable?","opciones":["Complementar la pesca extractiva","Sustituir al mar","Prohibir las capturas","Aumentar la contaminación"],"correcta":0},{"pregunta":"¿Qué papel tiene el consumidor?","opciones":["Preferir productos con etiquetas sostenibles","Es irrelevante","Decide los precios solo","Controla las mareas"],"correcta":0}]'::jsonb),

('geografia', 'bachillerato', '{2}', 'Ordenación del territorio en España', 'La ordenación del territorio es la disciplina que se ocupa de planificar los usos del suelo y las infraestructuras en un espacio determinado, buscando un desarrollo equilibrado, sostenible y coherente con los recursos disponibles. En España, esta competencia corresponde principalmente a las comunidades autónomas, que elaboran directrices, planes territoriales y normativas específicas, mientras que el Estado fija el marco básico y los ayuntamientos desarrollan los planes urbanísticos locales. La ordenación del territorio aborda cuestiones tan variadas como la distribución de las áreas industriales y residenciales, la protección de los paisajes y del patrimonio natural, la prevención de riesgos como inundaciones e incendios, la planificación de las infraestructuras de transporte y energía, la gestión del agua, la promoción de la actividad agrícola y turística o el reequilibrio entre zonas densamente pobladas y espacios rurales. La experiencia acumulada muestra que la falta de una ordenación rigurosa genera problemas importantes: urbanización dispersa, pérdida de suelos fértiles, fragmentación de hábitats, conflictos de uso y déficits en servicios públicos. Por el contrario, una planificación bien concebida contribuye a la cohesión territorial, a la calidad de vida y a la sostenibilidad ambiental. Los retos actuales de la ordenación del territorio en España incluyen la adaptación al cambio climático, el reto demográfico, la transición energética, la movilidad sostenible y la regeneración urbana. Todo ello requiere participación ciudadana, coordinación entre administraciones, evaluación rigurosa de las decisiones y una visión a largo plazo, más allá de los ciclos políticos y de los intereses particulares de cada territorio.',
'[{"pregunta":"¿A quién corresponde la competencia principal?","opciones":["A las comunidades autónomas","A la Unión Europea en exclusiva","A los bancos centrales","A las universidades"],"correcta":0},{"pregunta":"¿Qué problema genera la falta de ordenación?","opciones":["Urbanización dispersa y pérdida de suelos fértiles","Una mayor biodiversidad siempre","Un aumento automático del empleo","Una reducción del turismo"],"correcta":0},{"pregunta":"¿Qué reto actual se menciona?","opciones":["Adaptación al cambio climático","El regreso a la agricultura romana","La supresión de ayuntamientos","La prohibición de la vivienda"],"correcta":0},{"pregunta":"¿Qué visión requiere una buena ordenación?","opciones":["A largo plazo y coordinada","A corto plazo y fragmentada","Solo política","Solo técnica sin participación"],"correcta":0}]'::jsonb);


