-- ============================================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('economia-empresa', 'bachillerato', '{2}', 'Startups: del garaje al mercado global', 'Las startups son empresas emergentes que buscan desarrollar modelos de negocio innovadores y escalables, generalmente apoyándose en tecnología digital y con la ambición de crecer rápidamente en mercados nacionales o internacionales. A diferencia de una pyme tradicional, una startup suele centrarse en descubrir y validar una propuesta de valor nueva, operando con elevada incertidumbre y con recursos inicialmente limitados. Sus promotores combinan formación técnica, creatividad y una fuerte tolerancia al riesgo, apoyándose con frecuencia en mentores, incubadoras y aceleradoras. El ciclo vital de una startup atraviesa varias fases: idea, prototipo, validación temprana con usuarios, ronda inicial de financiación, crecimiento, escalado internacional y, si tiene éxito, consolidación o adquisición por empresas mayores. Cada fase requiere habilidades diferentes y plantea retos distintos, desde la definición del producto mínimo viable hasta la construcción de un equipo sólido y la captación de clientes recurrentes. La financiación es uno de los aspectos más críticos. Junto al ahorro propio y el apoyo familiar, las startups recurren a business angels, fondos de capital riesgo, rondas de financiación sucesivas y, en ocasiones, crowdfunding. Cada instrumento tiene sus condiciones y su impacto en el reparto de la propiedad. España ha visto florecer un ecosistema emprendedor en los últimos años, con polos destacados en Madrid, Barcelona, Valencia y Bilbao, impulsado por universidades, eventos, programas públicos y una creciente cultura emprendedora. Aunque no todas las startups triunfan, su papel en la innovación, la generación de empleo cualificado y la transformación de sectores tradicionales es fundamental para la competitividad del tejido económico.',
'[{"pregunta":"¿Qué caracteriza a una startup?","opciones":["Innovación escalable y alta incertidumbre","Rutina absoluta y bajos riesgos","Ausencia de clientes","Proveedores únicos solo"],"correcta":0},{"pregunta":"¿Qué instrumento de financiación se menciona?","opciones":["Business angels y capital riesgo","Subvenciones familiares automáticas","Herencias obligatorias","Créditos agrícolas únicamente"],"correcta":0},{"pregunta":"¿Qué fases atraviesa el ciclo vital?","opciones":["Idea, prototipo, validación, crecimiento","Fundación, cierre, fundación","Idea y jubilación","Crecimiento y quiebra directa"],"correcta":0},{"pregunta":"¿Qué polos se mencionan en España?","opciones":["Madrid, Barcelona, Valencia y Bilbao","Soria y Teruel","Jaén y Huelva","Lugo y Orense"],"correcta":0}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'La revolución fintech', 'El término fintech designa el uso de tecnologías digitales para transformar los servicios financieros tradicionales, abarcando desde los pagos móviles hasta la gestión automatizada de inversiones, pasando por los préstamos entre particulares, las criptomonedas, los neobancos y las aplicaciones de ahorro inteligente. Estas soluciones pretenden ofrecer una experiencia más rápida, intuitiva y barata que la de las entidades financieras clásicas, aprovechando la infraestructura móvil, la inteligencia artificial y el análisis masivo de datos. Para los consumidores, la fintech aporta ventajas claras: transferencias internacionales más económicas, apertura de cuentas sin papeleo, categorización automática de gastos, acceso a inversiones antes reservadas a grandes capitales, asesoramiento personalizado mediante algoritmos y visibilidad en tiempo real de las finanzas personales. También para los emprendedores y las pequeñas empresas supone acceso a crédito, facturación digital, pagos online y herramientas de gestión que antes eran caras o inaccesibles. Sin embargo, el sector plantea retos importantes. La regulación debe adaptarse a nuevos modelos sin ahogar la innovación ni poner en riesgo a los usuarios, garantizando la protección de los datos, la prevención del blanqueo de capitales y la solvencia de las plataformas. La competencia entre bancos tradicionales, fintechs y grandes empresas tecnológicas redefine el mapa del sector financiero, obligando a las entidades clásicas a digitalizarse rápidamente. La inclusión financiera es otro objetivo: llevar servicios básicos a colectivos que antes estaban fuera del sistema. En conjunto, la fintech transforma la relación de las personas con el dinero y exige una educación financiera actualizada para aprovechar sus oportunidades de forma responsable.',
'[{"pregunta":"¿Qué abarca el término fintech?","opciones":["Tecnologías digitales aplicadas a servicios financieros","Impresoras 3D exclusivamente","Agricultura de precisión","Industria pesada"],"correcta":0},{"pregunta":"¿Qué ventaja ofrece al consumidor?","opciones":["Transferencias más económicas y apertura sin papeleo","Mayor coste siempre","Acceso limitado","Mayor burocracia"],"correcta":0},{"pregunta":"¿Qué reto plantea al regulador?","opciones":["Adaptarse sin ahogar la innovación","Prohibir todos los bancos","Eliminar los móviles","Cerrar internet"],"correcta":0},{"pregunta":"¿Qué otro objetivo persigue?","opciones":["La inclusión financiera","La exclusión de los jóvenes","El aislamiento comercial","El retroceso tecnológico"],"correcta":0}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'Economía circular: un nuevo modelo productivo', 'La economía circular propone superar el modelo lineal tradicional, basado en extraer, fabricar, usar y desechar, para sustituirlo por un sistema en el que los materiales y los productos permanezcan el mayor tiempo posible dentro del ciclo productivo. Sus principios clave son la reducción del consumo de recursos, el diseño de productos duraderos y reparables, la reutilización, el reciclaje, la remanufactura y la valorización de los residuos. El objetivo es desacoplar el crecimiento económico del consumo creciente de materias primas y minimizar los impactos ambientales asociados. La transición hacia esta economía requiere cambios profundos en las empresas, en las políticas públicas y en los hábitos de los consumidores. Las compañías deben repensar sus modelos de negocio para ofrecer servicios en lugar de solo productos, adoptar la ecoinnovación, colaborar con sus proveedores y clientes y medir su impacto ambiental con indicadores rigurosos. Los gobiernos, por su parte, fijan normativas sobre residuos, responsabilidad ampliada del productor, incentivos fiscales y objetivos de reciclaje, y promueven la compra pública verde. Los consumidores, al elegir productos con eco-etiquetas, prolongar la vida útil de los bienes o participar en sistemas de reutilización, contribuyen directamente al éxito del modelo. La economía circular no solo tiene sentido ambiental: también genera oportunidades económicas, nuevos empleos verdes, innovación tecnológica y mayor resiliencia frente a la volatilidad de los precios de las materias primas. Los ejemplos exitosos, tanto en industria como en servicios, muestran que es posible reducir costes, fidelizar clientes y contribuir al mismo tiempo a la sostenibilidad del planeta y al bienestar colectivo.',
'[{"pregunta":"¿Qué modelo busca superar la economía circular?","opciones":["El lineal de extraer, fabricar, usar y desechar","El ecológico puro","El agrícola biológico","El artesanal tradicional"],"correcta":0},{"pregunta":"¿Qué principios destaca el texto?","opciones":["Reducción, reutilización, reciclaje y remanufactura","Consumo acelerado","Eliminación masiva","Exportación única"],"correcta":0},{"pregunta":"¿Qué aportan las empresas?","opciones":["Nuevos modelos basados en servicios y ecoinnovación","Producción sin límites","Eliminación de garantías","Obsolescencia máxima"],"correcta":0},{"pregunta":"¿Qué oportunidades económicas genera?","opciones":["Empleos verdes y mayor resiliencia","Desempleo masivo","Colapso industrial","Dependencia total de materias primas"],"correcta":0}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'El comercio electrónico y su impacto', 'El comercio electrónico, o e-commerce, ha experimentado un crecimiento extraordinario en las últimas décadas y ha transformado de forma profunda la manera en que las empresas venden y los consumidores compran. Plataformas globales, tiendas online de marcas reconocidas, marketplaces especializados y pequeños negocios digitales conviven en un ecosistema que abarca prácticamente todas las categorías de productos y servicios. Para los consumidores, las ventajas son evidentes: comparación fácil de precios, acceso a una oferta global, entregas rápidas, opiniones de otros usuarios y opciones de pago variadas. Para las empresas, el comercio electrónico supone nuevas oportunidades de llegar a mercados antes inaccesibles, analizar el comportamiento de los clientes con detalle y ajustar su oferta en tiempo real. Sin embargo, también plantea retos importantes. Los comercios tradicionales deben reinventarse para seguir siendo competitivos, integrando canales físicos y digitales en estrategias omnicanal. La logística se convierte en un factor clave, con presiones para reducir los tiempos de entrega y, a la vez, minimizar el impacto ambiental de los envíos. La protección de los datos personales, la ciberseguridad y la lucha contra el fraude exigen inversiones constantes y una legislación actualizada. Por otro lado, el comercio electrónico plantea debates sobre las condiciones laborales en almacenes y reparto, la competencia desigual con pequeños negocios y el impacto fiscal de las plataformas transnacionales. La regulación europea intenta abordar estos asuntos con normas sobre servicios digitales, mercados digitales y derechos de los consumidores. El futuro del sector estará marcado por la personalización, la sostenibilidad, la inteligencia artificial y nuevas formas de pago y entrega.',
'[{"pregunta":"¿Qué ventaja ofrece el e-commerce a los consumidores?","opciones":["Acceso a oferta global y comparación de precios","Menos información","Tiempos de espera mayores","Menores opciones de pago"],"correcta":0},{"pregunta":"¿Qué estrategia deben adoptar los comercios tradicionales?","opciones":["Omnicanal integrando físico y digital","Exclusivamente físico","Cerrar todas sus tiendas","Imprimir catálogos en papel"],"correcta":0},{"pregunta":"¿Qué factor se convierte en clave?","opciones":["La logística y los tiempos de entrega","La astronomía","La tipografía antigua","La minería del oro"],"correcta":0},{"pregunta":"¿Qué marcará el futuro del sector?","opciones":["Personalización, sostenibilidad e IA","El retorno al trueque","La eliminación de envíos","La prohibición del pago digital"],"correcta":0}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'Inversión socialmente responsable', 'La inversión socialmente responsable, conocida por las siglas ISR, integra criterios ambientales, sociales y de buen gobierno en las decisiones de inversión, junto a los tradicionales criterios financieros. Los inversores que adoptan este enfoque buscan que su dinero contribuya a un desarrollo sostenible y apoye empresas que gestionan correctamente su impacto en el planeta, en las personas y en la comunidad, sin renunciar necesariamente a obtener rentabilidad. Los criterios conocidos como ESG, ambientales, sociales y de gobernanza, se aplican mediante distintas estrategias: exclusión de sectores controvertidos como las armas o el tabaco, selección de empresas con las mejores prácticas dentro de su sector, inversión temática en energía limpia o educación, integración de los factores ESG en el análisis financiero convencional y compromiso activo con las compañías mediante el voto en las juntas y el diálogo con los gestores. La demanda de ISR ha crecido de forma notable, impulsada por particulares, fondos de pensiones, aseguradoras y grandes instituciones. Los reguladores europeos exigen cada vez más transparencia sobre los riesgos climáticos y los impactos sociales, y nuevas normativas clasifican los productos financieros sostenibles para evitar el llamado greenwashing. Los estudios empíricos sugieren que la ISR no implica necesariamente menor rentabilidad a largo plazo y puede reducir riesgos relacionados con controversias, sanciones o pérdidas de reputación. Para que la ISR cumpla sus objetivos, es imprescindible disponer de datos de calidad, metodologías rigurosas y educación financiera del inversor, de modo que las decisiones estén basadas en información fiable y no solo en etiquetas comerciales superficiales.',
'[{"pregunta":"¿Qué criterios integra la ISR además de los financieros?","opciones":["Ambientales, sociales y de gobernanza","Solo de producción","Solo publicitarios","Solo estéticos"],"correcta":0},{"pregunta":"¿Qué estrategia se menciona?","opciones":["Exclusión de sectores controvertidos","Obligación de invertir en armas","Rechazo de la energía limpia","Desinterés por la transparencia"],"correcta":0},{"pregunta":"¿Qué pretenden evitar las normativas europeas?","opciones":["El greenwashing","La inversión privada","La transparencia","Los fondos verdes"],"correcta":0},{"pregunta":"¿Qué es imprescindible para que cumpla sus objetivos?","opciones":["Datos de calidad y metodologías rigurosas","Información aleatoria","Ausencia de análisis","Marketing puramente emocional"],"correcta":0}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'La transformación digital de la empresa', 'La transformación digital es el proceso mediante el cual las empresas integran de forma estratégica las tecnologías digitales en todos sus procesos, productos, servicios y modelos de negocio para adaptarse a un entorno cada vez más tecnológico y competitivo. No se trata solo de digitalizar documentos o adoptar herramientas aisladas, sino de repensar cómo se trabaja, cómo se ofrece valor al cliente, cómo se gestionan los datos y cómo se toman las decisiones. Una empresa realmente transformada utiliza la nube para flexibilizar sus recursos, explota los datos para comprender a sus clientes, automatiza procesos rutinarios, favorece el trabajo colaborativo y experimenta con nuevas propuestas con agilidad. El proceso exige cambios importantes en la cultura organizativa: mayor autonomía de los equipos, disposición a aprender continuamente, trabajo interdisciplinar, liderazgo abierto y un papel reforzado del departamento tecnológico en las decisiones estratégicas. También supone una inversión significativa, que debe planificarse con cuidado para obtener un retorno razonable y gestionar los riesgos. Los beneficios potenciales incluyen una mejor experiencia del cliente, la entrada en nuevos mercados, la reducción de costes, la innovación en productos y la capacidad de responder más rápido a los cambios del entorno. Entre los retos se encuentran la falta de talento cualificado, la resistencia al cambio, la ciberseguridad, la gobernanza de los datos y la necesidad de mantener la coherencia entre estrategia y operaciones. Las empresas que afrontan la transformación digital con una visión clara, una ejecución disciplinada y atención a las personas obtienen ventajas competitivas duraderas frente a quienes se limitan a seguir la moda tecnológica sin un plan estructurado.',
'[{"pregunta":"¿Qué no es la transformación digital?","opciones":["Solo digitalizar documentos","Integrar estratégicamente tecnologías","Repensar procesos","Explotar datos"],"correcta":0},{"pregunta":"¿Qué cambios culturales exige?","opciones":["Mayor autonomía y aprendizaje continuo","Rigidez absoluta","Jerarquías estrictas e inmóviles","Aislamiento de los equipos"],"correcta":0},{"pregunta":"¿Qué beneficio potencial menciona?","opciones":["Mejor experiencia del cliente y entrada en nuevos mercados","Mayor distancia con los clientes","Reducción del personal obligatoria","Desaparición total de la competencia"],"correcta":0},{"pregunta":"¿Qué reto aparece?","opciones":["Falta de talento y ciberseguridad","Abundancia permanente de recursos","Ausencia de competencia","Exceso de burocracia papel"],"correcta":0}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'Las franquicias como forma de expansión', 'La franquicia es un modelo de negocio en el que una empresa, llamada franquiciador, cede a otras, los franquiciados, el derecho a utilizar su marca, sus productos, sus procedimientos y, en general, todo su saber hacer, a cambio de una contraprestación económica que suele incluir un canon de entrada y royalties periódicos. Este esquema permite al franquiciador expandirse con rapidez sin asumir toda la inversión que supondría abrir nuevos establecimientos por cuenta propia, mientras que el franquiciado se beneficia de una marca reconocida, un modelo probado, apoyo en la formación y la gestión, y menor riesgo que al emprender de forma totalmente independiente. Sectores como la hostelería, la moda, los servicios personales o la educación han recurrido ampliamente a este sistema, que explica el éxito internacional de muchas cadenas conocidas. No obstante, la franquicia no está exenta de riesgos. El franquiciado debe respetar las normas del franquiciador, lo que limita su libertad para adaptar el negocio a particularidades locales; el éxito depende de la calidad del contrato, del apoyo real ofrecido y de la buena marcha global de la cadena; y la saturación del mercado o errores en la elección de la ubicación pueden comprometer la rentabilidad. Por su parte, el franquiciador debe seleccionar cuidadosamente a sus socios, mantener la coherencia de la marca, ofrecer innovación constante y gestionar posibles conflictos. La legislación regula estos acuerdos para proteger a las dos partes y garantizar transparencia. Cuando se diseña y gestiona bien, la franquicia se convierte en una vía eficaz de crecimiento empresarial y en una oportunidad para emprendedores que prefieren apoyarse en un proyecto consolidado y operativo.',
'[{"pregunta":"¿Qué cede el franquiciador?","opciones":["Marca, productos, procedimientos y saber hacer","Sus acciones en bolsa","Sus oficinas centrales","Su sede fiscal"],"correcta":0},{"pregunta":"¿Qué debe pagar el franquiciado normalmente?","opciones":["Canon de entrada y royalties","Solo impuestos municipales","Nada en absoluto","Una cuota aleatoria"],"correcta":0},{"pregunta":"¿Qué limitación tiene el franquiciado?","opciones":["Debe respetar las normas del franquiciador","Puede cambiar la marca","Puede vender otros productos libremente","No tiene obligaciones"],"correcta":0},{"pregunta":"¿Qué deben mantener los franquiciadores?","opciones":["La coherencia de la marca e innovación","La opacidad total","La ausencia de contratos","La ignorancia del mercado"],"correcta":0}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'Crowdfunding: la financiación participativa', 'El crowdfunding, o financiación participativa, es un modelo mediante el cual personas, emprendedores u organizaciones obtienen fondos para proyectos, negocios o causas sumando pequeñas aportaciones de un gran número de contribuyentes, generalmente a través de plataformas digitales. Existen distintas modalidades. En el crowdfunding de recompensa, los patrocinadores reciben un bien o experiencia a cambio de su contribución. En el crowdfunding de donación, las aportaciones apoyan causas sociales o culturales sin esperar contraprestación material. El crowdfunding de préstamo, también conocido como crowdlending, permite a los participantes prestar dinero a un proyecto y recibir una remuneración con intereses. Por último, el crowdfunding de inversión ofrece a los contribuyentes una participación en el capital de la empresa que lanza la campaña. Para los emprendedores, el crowdfunding supone una alternativa a la financiación tradicional cuando los bancos son reacios a conceder crédito o cuando se busca al mismo tiempo validar la demanda del producto y construir una comunidad en torno a él. Para los contribuyentes, es una oportunidad de apoyar iniciativas que les ilusionan, acceder a proyectos innovadores o diversificar sus inversiones. Sin embargo, también existen riesgos: proyectos que no llegan a ejecutarse, falta de transparencia, dificultades para recuperar el dinero o rentabilidades menores de las esperadas. La legislación europea y nacional regula las plataformas, exige información clara para los inversores y establece límites a las cantidades aportadas y a los tipos de proyectos. Bien utilizado, el crowdfunding democratiza el acceso a la financiación, fomenta la innovación y contribuye a un ecosistema emprendedor más diverso y accesible.',
'[{"pregunta":"¿Qué modalidad ofrece participación en el capital?","opciones":["Crowdfunding de inversión","Crowdfunding de recompensa","Crowdfunding de donación","Crowdfunding de préstamo únicamente"],"correcta":0},{"pregunta":"¿Qué ventaja aporta a los emprendedores?","opciones":["Alternativa cuando los bancos son reacios","Mayor coste fijo","Menor visibilidad","Imposibilidad de construir comunidad"],"correcta":0},{"pregunta":"¿Qué riesgo se menciona?","opciones":["Proyectos que no se ejecutan","Rentabilidades infinitas","Absoluta ausencia de riesgo","Comisiones cero garantizadas"],"correcta":0},{"pregunta":"¿Qué hace la legislación?","opciones":["Regula plataformas y exige transparencia","Prohíbe toda modalidad","Elimina los contratos","Permite la opacidad total"],"correcta":0}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'Fusiones y adquisiciones empresariales', 'Las fusiones y adquisiciones, conocidas internacionalmente por las siglas M y A, son operaciones estratégicas mediante las cuales una empresa se une con otra, compra una parte mayoritaria de sus acciones o absorbe sus activos. Estas operaciones pueden responder a múltiples objetivos: crecer rápidamente, acceder a nuevos mercados, diversificar productos, adquirir tecnología o talento, lograr economías de escala, reducir competencia o mejorar la estructura financiera. Desde el punto de vista jurídico y fiscal, implican procesos complejos que requieren estudios previos detallados, conocidos como due diligence, para evaluar los riesgos, la situación financiera, los pasivos ocultos, los contratos vigentes y la compatibilidad de culturas empresariales. La ejecución puede incluir fusiones por absorción, fusiones por creación de una nueva sociedad, adquisiciones de paquetes accionariales o compras hostiles cuando el consejo de la empresa objetivo se opone a la operación. El éxito de estas operaciones depende en gran medida de la preparación, del precio pagado y de la integración posterior, que suele ser la fase más delicada: unir equipos, sistemas informáticos, procesos, marcas y estilos directivos muy diferentes. Los fracasos en integración explican una parte importante de las operaciones que no alcanzan los objetivos anunciados. Los reguladores supervisan las grandes fusiones para evitar concentraciones perjudiciales para la competencia y, por tanto, para los consumidores. Las fusiones y adquisiciones son, al mismo tiempo, instrumentos poderosos de reestructuración empresarial y decisiones arriesgadas que afectan a miles de empleados, proveedores y accionistas, y que requieren una visión estratégica, ética y a largo plazo por parte de los equipos directivos que las promueven.',
'[{"pregunta":"¿Qué significan las siglas M y A?","opciones":["Fusiones y adquisiciones","Marketing y análisis","Management y administración","Mayoría y asamblea"],"correcta":0},{"pregunta":"¿Qué es la due diligence?","opciones":["Estudios previos para evaluar riesgos y situación","Un impuesto específico","Una subvención automática","Un canon único"],"correcta":0},{"pregunta":"¿Por qué fracasan muchas fusiones?","opciones":["Por problemas de integración","Por exceso de beneficios","Por carecer de empleados","Por falta de clientes"],"correcta":0},{"pregunta":"¿Qué supervisan los reguladores?","opciones":["Las concentraciones que perjudiquen la competencia","Los salarios mínimos","Las primas de seguros","Las vacaciones del personal"],"correcta":0}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'El emprendimiento social', 'El emprendimiento social es la actividad de crear organizaciones que buscan resolver problemas sociales o ambientales mediante modelos de negocio sostenibles. A diferencia de las empresas tradicionales, cuyo objetivo principal es maximizar el beneficio para los accionistas, las empresas sociales combinan la generación de ingresos con una misión explícita de impacto positivo. Esta misión puede ser muy variada: facilitar el acceso a la educación o la sanidad en comunidades vulnerables, integrar laboralmente a personas con discapacidad, promover la agricultura ecológica, ofrecer microcréditos a emprendedores de países en desarrollo, reducir residuos mediante la economía circular, o impulsar la participación de las mujeres en el mercado laboral. Los emprendedores sociales suelen combinar pasión por la causa, capacidad de gestión empresarial y creatividad para diseñar soluciones innovadoras con recursos limitados. Recurren a distintas fuentes de financiación, como capital paciente, fundaciones, banca ética, subvenciones públicas, crowdfunding y, cada vez más, inversores de impacto que buscan rendimiento financiero junto a resultados sociales medibles. La medición del impacto es un desafío central: exige definir indicadores claros, recoger datos fiables y comunicar con transparencia los resultados, más allá de los tradicionales informes financieros. El emprendimiento social se apoya en redes de apoyo, incubadoras especializadas, programas universitarios y premios que dan visibilidad a los proyectos. Los marcos legales evolucionan para reconocer estas formas organizativas mediante figuras como las empresas con propósito o las sociedades de beneficio e interés común. Aunque no es una panacea para todos los problemas, el emprendimiento social demuestra que es posible unir rentabilidad y compromiso social dentro de una misma empresa.',
'[{"pregunta":"¿Qué combinan las empresas sociales?","opciones":["Ingresos y misión de impacto positivo","Beneficios y prohibiciones","Subvenciones y opacidad","Activos y extinción"],"correcta":0},{"pregunta":"¿Qué ejemplo de misión se cita?","opciones":["Integrar laboralmente a personas con discapacidad","Aumentar las emisiones","Reducir el empleo","Cerrar escuelas"],"correcta":0},{"pregunta":"¿Qué es un inversor de impacto?","opciones":["Busca rendimiento financiero junto a resultados sociales","Invierte en azar","Solo compra oro","Rechaza toda sostenibilidad"],"correcta":0},{"pregunta":"¿Qué desafío central tiene?","opciones":["La medición del impacto","Evitar las ganancias","Eliminar la transparencia","Suprimir los datos"],"correcta":0}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'Sostenibilidad empresarial y ODS', 'La sostenibilidad empresarial consiste en integrar en la estrategia y en las operaciones de las empresas las tres dimensiones del desarrollo sostenible: la económica, la ambiental y la social. Durante mucho tiempo, la empresa se juzgó casi exclusivamente por sus resultados financieros. Hoy, sin embargo, la sociedad, los reguladores, los consumidores, los empleados y los inversores exigen una visión más amplia. Los 17 Objetivos de Desarrollo Sostenible aprobados por las Naciones Unidas en 2015 ofrecen un marco común para alinear los esfuerzos de empresas, gobiernos y ciudadanía. Estos objetivos abarcan temas como la erradicación de la pobreza, el acceso a la educación y la salud, la igualdad de género, la acción climática, la producción responsable, el trabajo decente y las alianzas para el desarrollo. Las empresas pueden contribuir a ellos mediante el rediseño de sus productos, la reducción de emisiones, el uso responsable de los recursos, la gestión ética de su cadena de suministro, el fomento de la diversidad, la innovación al servicio del bien común y la publicación de informes no financieros rigurosos que permitan a los grupos de interés evaluar su desempeño. Los beneficios son múltiples: fidelización de clientes y empleados, mejora reputacional, anticipación de riesgos regulatorios, acceso preferente a financiación sostenible y capacidad de innovación. Sin embargo, la sostenibilidad empresarial no debe quedarse en un ejercicio de imagen. Requiere objetivos verificables, gobernanza sólida y coherencia entre lo que la empresa dice y hace. Es una oportunidad y, al mismo tiempo, una responsabilidad compartida entre directivos, trabajadores, consumidores, inversores y reguladores para construir un modelo económico al servicio de las personas y del planeta.',
'[{"pregunta":"¿Cuántos Objetivos de Desarrollo Sostenible aprobó la ONU?","opciones":["17","5","10","25"],"correcta":0},{"pregunta":"¿Qué dimensiones integra la sostenibilidad empresarial?","opciones":["Económica, ambiental y social","Solo económica","Solo ambiental","Solo marketing"],"correcta":0},{"pregunta":"¿Qué beneficios aporta?","opciones":["Fidelización, reputación y acceso a financiación sostenible","Pérdida de clientes","Reducción de innovación","Bloqueo regulatorio"],"correcta":0},{"pregunta":"¿Qué requiere la sostenibilidad empresarial?","opciones":["Objetivos verificables y coherencia","Imagen sin contenido","Objetivos secretos","Exclusión de los grupos de interés"],"correcta":0}]'::jsonb),

('economia-empresa', 'bachillerato', '{2}', 'Industria 4.0 y fábricas inteligentes', 'La Industria 4.0 designa la nueva revolución industrial basada en la digitalización integral de los procesos productivos mediante tecnologías como el internet de las cosas, la computación en la nube, el big data, la inteligencia artificial, la robótica avanzada, la fabricación aditiva y los sistemas ciberfísicos. Las fábricas inteligentes conectan máquinas, productos, operarios y clientes en una red continua que permite supervisar en tiempo real los procesos, detectar anomalías, predecir fallos antes de que ocurran, ajustar dinámicamente la producción a la demanda y personalizar los productos al mismo coste que la producción en serie. Los beneficios esperados son notables: mayor productividad, reducción de costes y defectos, flexibilidad para atender pedidos variados, mejor calidad, más seguridad laboral al delegar tareas peligrosas a los robots, y posibilidad de ofrecer nuevos servicios derivados de los datos recogidos. Para las empresas, adoptar la Industria 4.0 supone una transformación profunda que requiere inversión en infraestructura tecnológica, formación del personal, rediseño de procesos y nuevas estructuras organizativas más colaborativas. También plantea retos importantes: ciberseguridad de los equipos conectados, dependencia de proveedores tecnológicos, necesidad de estándares compartidos, protección de los datos industriales y preocupación por los efectos sobre el empleo, especialmente en tareas rutinarias. Los gobiernos impulsan estrategias nacionales y europeas para apoyar esta transición, con especial atención a las pymes, que suelen tener más dificultades para adoptar estas tecnologías. La Industria 4.0 no es un simple cambio de maquinaria, sino una transformación cultural y estratégica que redefine el papel del trabajo humano, aprovechando al máximo la colaboración entre personas y máquinas inteligentes.',
'[{"pregunta":"¿Qué tecnologías componen la Industria 4.0?","opciones":["IoT, nube, big data, IA, robótica","Solo maquinaria del siglo XIX","Papel y lápiz","Solo cinta transportadora"],"correcta":0},{"pregunta":"¿Qué permite la supervisión en tiempo real?","opciones":["Detectar anomalías y predecir fallos","Ignorar los procesos","Aumentar los defectos","Ralentizar la producción"],"correcta":0},{"pregunta":"¿Qué reto plantea?","opciones":["Ciberseguridad y efectos sobre el empleo","Exceso absoluto de trabajadores","Ausencia de competencia","Inexistencia de estándares obsoletos"],"correcta":0},{"pregunta":"¿Quiénes reciben especial atención en las estrategias públicas?","opciones":["Las pymes","Solo las multinacionales","Las fundaciones culturales","Los clubes deportivos"],"correcta":0}]'::jsonb);

